// ═══════════════════════════════════════════════════════════
// Lume Meridian — SPA Hash Router
// ═══════════════════════════════════════════════════════════

const MeridianRouter = (function() {
  const routes = new Map()
  const listeners = []
  let currentRoute = ""

  function register(hash, renderFn) {
    routes.set(hash, renderFn)
  }

  function navigate(hash) {
    window.location.hash = hash
  }

  function getCurrentHash() {
    return window.location.hash.replace("#", "") || "boot"
  }

  function render() {
    const hash = getCurrentHash()
    if (hash === currentRoute) return
    currentRoute = hash

    const container = dom.select("#m-page-container")
    if (!container) return

    const renderFn = routes.get(hash)
    if (renderFn) {
      dom.clear(container)
      renderFn(container)
      listeners.forEach(function(fn) { fn(hash) })
    } else {
      // Default to hero if unknown route
      const heroFn = routes.get("hero")
      if (heroFn) {
        dom.clear(container)
        heroFn(container)
      }
    }
  }

  function onChange(fn) {
    listeners.push(fn)
  }

  // Listen for hash changes
  window.addEventListener("hashchange", render)

  return { register: register, navigate: navigate, render: render, onChange: onChange, getCurrentHash: getCurrentHash }
})()


// ═══════════════════════════════════════════════════════════
// Lume Meridian — App Shell
// Navigation bar + page container + global footer
// ═══════════════════════════════════════════════════════════

const MeridianShell = (function() {
  let mobileMenuOpen = false

  function build() {
    const app = dom.select("#app")
    if (!app) return

    // Navigation bar
    const nav = dom.create("nav", { className: "m-nav", id: "m-nav" })
    const logo = dom.create("div", {
      className: "m-nav-logo",
      text: "MERIDIAN",
      onClick: function() { MeridianRouter.navigate("hero") }
    })
    const links = dom.create("div", { className: "m-nav-links", id: "m-nav-links" })

    const navItems = [
      { hash: "hero", label: "HOME" },
      { hash: "research", label: "ARCHITECTURE" },
      { hash: "control", label: "CONTROL" },
      { hash: "prototype", label: "PROTOTYPE" },
      { hash: "fractal", label: "4/42 LAW" },
      { hash: "canon", label: "CANON" },
    ]

    navItems.forEach(function(item) {
      const link = dom.create("button", {
        className: "m-nav-link",
        text: item.label,
        attrs: { "data-route": item.hash },
        onClick: function() {
          MeridianRouter.navigate(item.hash)
          if (mobileMenuOpen) toggleMobile()
        }
      })
      dom.add_child(links, link)
    })

    // Hamburger button
    const hamburger = dom.create("button", {
      className: "m-hamburger",
      id: "m-hamburger",
      onClick: function() { toggleMobile() }
    })
    dom.add_child(hamburger, dom.create("span"))
    dom.add_child(hamburger, dom.create("span"))
    dom.add_child(hamburger, dom.create("span"))

    // Patent badge
    const badge = dom.create("div", {
      className: "m-badge m-badge-info m-hide-mobile",
      html: "◆ PATENT PENDING",
      styles: { marginLeft: "12px" }
    })

    dom.add_child(nav, logo)
    dom.add_child(nav, links)
    dom.add_child(nav, badge)
    dom.add_child(nav, hamburger)

    // Page container
    const container = dom.create("div", {
      id: "m-page-container",
      styles: { width: "100%", minHeight: "100vh", paddingTop: "60px" }
    })

    dom.add_child(app, nav)
    dom.add_child(app, container)

    // Update active nav link on route change
    MeridianRouter.onChange(function(hash) {
      const allLinks = dom.select_all(".m-nav-link")
      allLinks.forEach(function(l) { dom.remove_class(l, "active") })
      const activeLink = dom.select('.m-nav-link[data-route="' + hash + '"]')
      if (activeLink) { dom.add_class(activeLink, "active") }
    })
  }

  function toggleMobile() {
    const links = dom.select("#m-nav-links")
    if (links) {
      mobileMenuOpen = !mobileMenuOpen
      if (mobileMenuOpen) {
        dom.add_class(links, "open")
      } else {
        dom.remove_class(links, "open")
      }
    }
  }

  function hideNav() {
    const nav = dom.select("#m-nav")
    if (nav) { nav.style.transform = "translateY(-100%)"; nav.style.transition = "transform 0.5s ease"; }
  }

  function showNav() {
    const nav = dom.select("#m-nav")
    if (nav) { nav.style.transform = "translateY(0)"; nav.style.transition = "transform 0.5s ease"; }
  }

  // Global footer builder — call from any page
  function buildFooter(container) {
    const footer = dom.create("footer", { className: "m-footer" })

    const grid = dom.create("div", { className: "m-footer-grid" })

    // Brand column
    const brandCol = dom.create("div")
    dom.add_child(brandCol, dom.create("div", {
      text: "MERIDIAN",
      styles: { fontSize: "18px", fontWeight: "900", letterSpacing: "8px", color: "#06b6d4", marginBottom: "12px" }
    }))
    dom.add_child(brandCol, dom.create("p", {
      text: "Deterministic wireless-energy routing architecture. Route energy like data — deterministic, auditable, safe.",
      styles: { fontSize: "13px", color: "rgba(255,255,255,0.4)", lineHeight: "1.7", maxWidth: "320px" }
    }))
    dom.add_child(brandCol, dom.create("div", {
      className: "m-badge m-badge-info",
      html: "◆ PATENT PENDING",
      styles: { marginTop: "16px" }
    }))
    dom.add_child(grid, brandCol)

    // Ecosystem column
    const ecoCol = dom.create("div")
    dom.add_child(ecoCol, dom.create("div", { text: "ECOSYSTEM", className: "m-footer-heading" }))
    const ecoLinks = [
      { text: "HydroCore", href: LINKS.hydrocore },
      { text: "Verdara Ultra", href: LINKS.verdara },
      { text: "Lume Language", href: LINKS.lume },
      { text: "Lume42", href: LINKS.lume42 },
      { text: "TrustShield", href: LINKS.trustshield },
      { text: "DarkWave Studios", href: LINKS.dwsc },
      { text: "GitHub", href: LINKS.github },
    ]
    ecoLinks.forEach(function(l) {
      const a = dom.create("a", { text: l.text, className: "m-footer-link", attrs: { href: l.href, target: "_blank", rel: "noopener" } })
      dom.add_child(ecoCol, a)
    })
    dom.add_child(grid, ecoCol)

    // Research column
    const resCol = dom.create("div")
    dom.add_child(resCol, dom.create("div", { text: "RESEARCH", className: "m-footer-heading" }))
    const resLinks = [
      { text: "Zenodo Community", href: LINKS.zenodo },
      { text: "ORCID Profile", href: LINKS.orcid },
      { text: "The Routed World", hash: "canon" },
      { text: "4/42 Fractal Law", hash: "fractal" },
    ]
    resLinks.forEach(function(l) {
      if (l.href) {
        const a = dom.create("a", { text: l.text, className: "m-footer-link", attrs: { href: l.href, target: "_blank", rel: "noopener" } })
        dom.add_child(resCol, a)
      } else {
        const btn = dom.create("button", { text: l.text, className: "m-footer-link", onClick: function() { MeridianRouter.navigate(l.hash) } })
        dom.add_child(resCol, btn)
      }
    })
    dom.add_child(grid, resCol)

    // Contact column
    const ctcCol = dom.create("div")
    dom.add_child(ctcCol, dom.create("div", { text: "CONTACT", className: "m-footer-heading" }))
    dom.add_child(ctcCol, dom.create("a", { text: "team@dwsc.io", className: "m-footer-link", attrs: { href: LINKS.email } }))
    dom.add_child(ctcCol, dom.create("div", { text: "Nashville, Tennessee", className: "m-footer-link", styles: { cursor: "default" } }))
    dom.add_child(ctcCol, dom.create("a", { text: "meridiancanon.com", className: "m-footer-link", attrs: { href: "https://meridiancanon.com", target: "_blank" } }))
    dom.add_child(grid, ctcCol)

    dom.add_child(footer, grid)

    // Bottom bar
    const bottom = dom.create("div", { className: "m-footer-bottom" })
    dom.add_child(bottom, dom.create("div", {
      className: "m-caption",
      html: "&copy; 2026 " + MERIDIAN_ORG + " &mdash; All rights reserved."
    }))
    dom.add_child(bottom, dom.create("div", {
      className: "m-caption",
      html: "v" + MERIDIAN_VERSION + " &mdash; BUILT WITH THE LUME PROGRAMMING LANGUAGE"
    }))
    dom.add_child(footer, bottom)

    dom.add_child(container, footer)
  }

  return { build: build, hideNav: hideNav, showNav: showNav, buildFooter: buildFooter }
})()


