// Lume Meridian — Simulation Engine
// Deterministic pathfinding, safety envelope, beam geometry
// ═══════════════════════════════════════════════════════════

const MeridianEngine = (function() {
  "use strict";

  // ── Constants (from the 9 papers) ──
  const SAFETY = {
    MAX_DENSITY: 1000,       /// W/m² maximum power density (directed beam)
    MAX_EXPOSURE_MS: 30000,  /// 30 seconds max exposure
    MIN_DECAY_RATE: 0.85,    /// minimum inverse-square decay
    FORBIDDEN_MARGIN: 20,    /// px margin around forbidden zones
    COLLAPSE_MS: 0.1,        /// <100μs fail-safe collapse
    BEAM_BASE_WIDTH: 12,     /// px base beam width
    MAX_RANGE_A: 400,        /// px max range for Class A anchors
    MAX_RANGE_B: 300,        /// px max range for Class B
    MAX_RANGE_C: 250,        /// px max range for Class C
    MAX_RANGE_D: 150,        /// px max range for Class D
  }

  const GEOMETRY_TYPES = {
    LINEAR: "linear",
    CURVED: "curved",
    MULTINODE: "multinode",
    DISTRIBUTED: "distributed",
    ADAPTIVE: "adaptive",
  }

  // ── State ──
  let anchors = []
  let devices = []
  let paths = []
  let walls = []
  let forbiddenZones = []
  let safetyLog = []
  let idCounter = 0
  let tickCount = 0
  let exposureMap = {}

  // ── Anchor Nodes ──
  function createAnchor(x, y, cls, label) {
    idCounter++
    const clsData = ANCHOR_CLASSES[cls] || ANCHOR_CLASSES.A
    const maxRange = cls === "A" ? SAFETY.MAX_RANGE_A :
                      cls === "B" ? SAFETY.MAX_RANGE_B :
                      cls === "C" ? SAFETY.MAX_RANGE_C : SAFETY.MAX_RANGE_D
    const anchor = {
      id: "A" + idCounter,
      x: x, y: y,
      cls: cls,
      data: clsData,
      maxPower: clsData.maxPower,
      currentPower: 0,
      maxRange: maxRange,
      active: true,
      label: label || ("Anchor " + idCounter),
      pulse: math.random() * math.PI * 2,
      spawnTime: Date.now(),
    }
    anchors.push(anchor)
    logSafety("ANCHOR_CREATED", anchor.id, "Class " + cls + " at (" + math.round(x) + "," + math.round(y) + ")")
    return anchor
  }

  // ── Device Profiles ──
  function createDevice(x, y, profile) {
    idCounter++
    const profileData = DEVICE_PROFILES[profile] || DEVICE_PROFILES.mobile
    const device = {
      id: "D" + idCounter,
      x: x, y: y,
      profile: profile,
      data: profileData,
      draw: profileData.draw,
      priority: profileData.priority,
      active: true,
      connected: false,
      connectedAnchor: null,
      label: profileData.name,
      pulse: math.random() * math.PI * 2,
    }
    devices.push(device)
    logSafety("DEVICE_REGISTERED", device.id, profileData.name + " — " + profileData.draw + "W draw")
    return device
  }

  // ── Deterministic Pathfinding ──
  function computePath(sourceId, targetId, geoType) {
    const src = anchors.find(function(a) { return a.id === sourceId })
    const tgt = anchors.find(function(a) { return a.id === targetId }) ||
                 devices.find(function(d) { return d.id === targetId })
    if (!src || !tgt) return null
    if (!src.active) return null

    const dx = tgt.x - src.x
    const dy = tgt.y - src.y
    const dist = math.sqrt(dx * dx + dy * dy)

    // Range check
    if (dist > src.maxRange) {
      logSafety("PATH_BLOCKED", src.id + "→" + tgt.id, "Distance " + math.round(dist) + "px exceeds max range " + src.maxRange + "px")
      return null
    }

    // Wall intersection check
    const blocked = walls.some(function(wall) {
      return lineIntersectsLine(src.x, src.y, tgt.x, tgt.y, wall.x1, wall.y1, wall.x2, wall.y2)
    })
    if (blocked) {
      logSafety("PATH_BLOCKED", src.id + "→" + tgt.id, "Wall obstruction detected")
      return null
    }

    // Forbidden zone check
    const forbidden = forbiddenZones.some(function(zone) {
      return lineIntersectsRect(src.x, src.y, tgt.x, tgt.y,
        zone.x - SAFETY.FORBIDDEN_MARGIN, zone.y - SAFETY.FORBIDDEN_MARGIN,
        zone.w + SAFETY.FORBIDDEN_MARGIN * 2, zone.h + SAFETY.FORBIDDEN_MARGIN * 2)
    })
    if (forbidden) {
      logSafety("PATH_BLOCKED", src.id + "→" + tgt.id, "Forbidden zone intersection")
      return null
    }

    // Compute beam geometry
    const geometry = computeBeamGeometry(src, tgt, geoType || GEOMETRY_TYPES.LINEAR, dist)

    // Compute efficiency and power delivery
    const decay = math.pow(SAFETY.MIN_DECAY_RATE, dist / 100)
    const efficiency = math.round(math.max(15, decay * 100))
    const deliveredPower = math.round((tgt.draw || src.maxPower * 0.5) * decay)
    const peakDensity = computePeakDensity(deliveredPower, geometry.beamWidth)

    // Safety check
    const safe = peakDensity <= SAFETY.MAX_DENSITY
    if (!safe) {
      logSafety("SAFETY_VIOLATION", src.id + "→" + tgt.id, "Peak density " + math.round(peakDensity) + " W/m² exceeds limit")
    }

    const path = {
      id: src.id + "→" + tgt.id,
      src: src.id,
      tgt: tgt.id,
      dist: math.round(dist),
      safe: safe,
      efficiency: efficiency,
      deliveredPower: deliveredPower,
      peakDensity: math.round(peakDensity * 10) / 10,
      geometry: geometry,
      geoType: geoType || GEOMETRY_TYPES.LINEAR,
      active: safe,
      created: Date.now(),
      particles: [],
    }

    // Update connectivity
    if (tgt.draw !== undefined) {
      tgt.connected = safe
      tgt.connectedAnchor = safe ? src.id : null
    }

    paths.push(path)
    if (safe) {
      logSafety("PATH_ACTIVE", path.id, geoType + " — " + efficiency + "% eff — " + deliveredPower + "W")
    }
    return path
  }

  // ── Beam Geometry ──
  function computeBeamGeometry(src, tgt, geoType, dist) {
    const baseWidth = SAFETY.BEAM_BASE_WIDTH
    const points = [{ x: src.x, y: src.y }]
    let beamWidth = baseWidth

    if (geoType === GEOMETRY_TYPES.LINEAR) {
      beamWidth = baseWidth
      points.push({ x: tgt.x, y: tgt.y })

    } else if (geoType === GEOMETRY_TYPES.CURVED) {
      // Quadratic bezier — curve around midpoint offset
      const mx = (src.x + tgt.x) / 2
      const my = (src.y + tgt.y) / 2
      const nx = -(tgt.y - src.y) * 0.3
      const ny = (tgt.x - src.x) * 0.3
      const cp = { x: mx + nx, y: my + ny }
      for (let t = 0.1; t <= 1.0; t += 0.1) {
        const u = 1 - t
        points.push({
          x: u * u * src.x + 2 * u * t * cp.x + t * t * tgt.x,
          y: u * u * src.y + 2 * u * t * cp.y + t * t * tgt.y,
        })
      }
      beamWidth = baseWidth * 1.4

    } else if (geoType === GEOMETRY_TYPES.MULTINODE) {
      // Multi-hop relay — route through 2 intermediate relay points
      const dx = tgt.x - src.x
      const dy = tgt.y - src.y
      const nx = -dy * 0.2
      const ny = dx * 0.2
      // Relay node 1 at ~33%
      points.push({ x: src.x + dx * 0.33 + nx, y: src.y + dy * 0.33 + ny })
      // Relay node 2 at ~66%
      points.push({ x: src.x + dx * 0.66 - nx, y: src.y + dy * 0.66 - ny })
      points.push({ x: tgt.x, y: tgt.y })
      beamWidth = baseWidth * 0.7

    } else if (geoType === GEOMETRY_TYPES.DISTRIBUTED) {
      // Distributed fan — wide spread beam through 3 parallel sub-paths
      const dx = tgt.x - src.x
      const dy = tgt.y - src.y
      const nx = -dy * 0.25
      const ny = dx * 0.25
      // Fan out at 25%, converge at 75%
      const mid1 = { x: src.x + dx * 0.25 + nx * 1.5, y: src.y + dy * 0.25 + ny * 1.5 }
      const mid2 = { x: src.x + dx * 0.5, y: src.y + dy * 0.5 }
      const mid3 = { x: src.x + dx * 0.75 - nx * 1.5, y: src.y + dy * 0.75 - ny * 1.5 }
      points.push(mid1)
      points.push(mid2)
      points.push(mid3)
      points.push({ x: tgt.x, y: tgt.y })
      beamWidth = baseWidth * 2.5

    } else if (geoType === GEOMETRY_TYPES.ADAPTIVE) {
      // Adaptive routing — pronounced sine wave showing dynamic path adjustment
      const steps = 12
      const amplitude = math.max(30, dist * 0.08)
      for (let i = 1; i <= steps; i++) {
        const t = i / steps
        const wave = math.sin(t * math.PI * 3) * amplitude * (1 - math.abs(t - 0.5) * 1.2)
        const dx = tgt.x - src.x
        const dy = tgt.y - src.y
        const nx = -dy / math.sqrt(dx * dx + dy * dy + 1)
        const ny = dx / math.sqrt(dx * dx + dy * dy + 1)
        const px = src.x + dx * t + nx * wave
        const py = src.y + dy * t + ny * wave
        points.push({ x: px, y: py })
      }
      beamWidth = baseWidth * 1.3
    }

    return { points: points, beamWidth: beamWidth, type: geoType }
  }

  // ── Safety Envelope ──
  function computePeakDensity(power, beamWidth) {
    // Convert pixel beam width to simulated meters (40px ≈ 1m)
    const beamMeters = math.max(0.1, beamWidth / 40)
    const area = beamMeters * beamMeters
    return power / area
  }

  function getDensityAt(x, y) {
    let total = 0
    paths.forEach(function(p) {
      if (!p.active) return
      const src = anchors.find(function(a) { return a.id === p.src })
      const tgt = anchors.find(function(a) { return a.id === p.tgt }) ||
                   devices.find(function(d) { return d.id === p.tgt })
      if (!src || !tgt) return
      const distToBeam = pointToLineDistance(x, y, src.x, src.y, tgt.x, tgt.y)
      if (distToBeam < p.geometry.beamWidth * 2) {
        const falloff = math.max(0, 1 - distToBeam / (p.geometry.beamWidth * 2))
        total += p.peakDensity * falloff * falloff
      }
    })
    return total
  }

  function evaluateAllSafety() {
    paths.forEach(function(p) {
      if (!p.active) return
      const src = anchors.find(function(a) { return a.id === p.src })
      if (!src || !src.active) {
        p.active = false
        p.safe = false
        logSafety("PATH_COLLAPSED", p.id, "Source anchor deactivated")
      }
    })
  }

  // ── Recalculate all paths ──
  function recalcAllPaths(overrideGeoType) {
    const oldPaths = paths.slice()
    paths = []
    oldPaths.forEach(function(op) {
      computePath(op.src, op.tgt, overrideGeoType || op.geoType)
    })
  }

  // ── Auto-connect devices to nearest anchor ──
  function autoConnect() {
    devices.forEach(function(dev) {
      if (!dev.active) return
      let bestAnchor = null
      let bestDist = Infinity
      anchors.forEach(function(a) {
        if (!a.active) return
        const dx = dev.x - a.x
        const dy = dev.y - a.y
        const d = math.sqrt(dx * dx + dy * dy)
        if (d < a.maxRange && d < bestDist) {
          bestDist = d
          bestAnchor = a
        }
      })
      if (bestAnchor) {
        const existingPath = paths.find(function(p) { return p.src === bestAnchor.id && p.tgt === dev.id })
        if (!existingPath) {
          const geo = dev.data.geometry || "linear"
          computePath(bestAnchor.id, dev.id, geo)
        }
      }
    })
  }

  // ── Geometry helpers ──
  function lineIntersectsLine(x1, y1, x2, y2, x3, y3, x4, y4) {
    const denom = (x1 - x2) * (y3 - y4) - (y1 - y2) * (x3 - x4)
    if (math.abs(denom) < 0.0001) return false
    const t = ((x1 - x3) * (y3 - y4) - (y1 - y3) * (x3 - x4)) / denom
    const u = -((x1 - x2) * (y1 - y3) - (y1 - y2) * (x1 - x3)) / denom
    return t >= 0 && t <= 1 && u >= 0 && u <= 1
  }

  function lineIntersectsRect(x1, y1, x2, y2, rx, ry, rw, rh) {
    return lineIntersectsLine(x1, y1, x2, y2, rx, ry, rx + rw, ry) ||
           lineIntersectsLine(x1, y1, x2, y2, rx + rw, ry, rx + rw, ry + rh) ||
           lineIntersectsLine(x1, y1, x2, y2, rx + rw, ry + rh, rx, ry + rh) ||
           lineIntersectsLine(x1, y1, x2, y2, rx, ry + rh, rx, ry)
  }

  function pointToLineDistance(px, py, x1, y1, x2, y2) {
    const dx = x2 - x1
    const dy = y2 - y1
    const lenSq = dx * dx + dy * dy
    if (lenSq === 0) return math.sqrt((px - x1) * (px - x1) + (py - y1) * (py - y1))
    let t = ((px - x1) * dx + (py - y1) * dy) / lenSq
    t = math.max(0, math.min(1, t))
    const projX = x1 + t * dx
    const projY = y1 + t * dy
    return math.sqrt((px - projX) * (px - projX) + (py - projY) * (py - projY))
  }

  // ── Safety Logger ──
  function logSafety(type, target, message) {
    const entry = {
      tick: tickCount,
      time: Date.now(),
      type: type,
      target: target,
      message: message,
    }
    safetyLog.push(entry)
    if (safetyLog.length > 200) safetyLog.shift()
  }

  // ── Tick ──
  function tick() {
    tickCount++
    evaluateAllSafety()
    // Accumulate exposure for connected devices
    devices.forEach(function(d) {
      if (d.connected) {
        if (!exposureMap[d.id]) exposureMap[d.id] = 0
        exposureMap[d.id] += 16  /// ~16ms per frame
        if (exposureMap[d.id] > SAFETY.MAX_EXPOSURE_MS) {
          logSafety("EXPOSURE_LIMIT", d.id, "Exceeded " + SAFETY.MAX_EXPOSURE_MS + "ms")
        }
      }
    })
  }

  // ── Reset ──
  function reset() {
    anchors = []
    devices = []
    paths = []
    walls = []
    forbiddenZones = []
    safetyLog = []
    exposureMap = {}
    idCounter = 0
    tickCount = 0
  }

  // ── Getters ──
  function getAnchors() { return anchors }
  function getDevices() { return devices }
  function getPaths() { return paths }
  function getWalls() { return walls }
  function getForbiddenZones() { return forbiddenZones }
  function getSafetyLog() { return safetyLog }
  function getMetrics() {
    const activePaths = paths.filter(function(p) { return p.active })
    const totalDelivered = activePaths.reduce(function(s, p) { return s + p.deliveredPower }, 0)
    const avgEfficiency = activePaths.length > 0 ?
      math.round(activePaths.reduce(function(s, p) { return s + p.efficiency }, 0) / activePaths.length) : 0
    const safeCount = activePaths.length
    const unsafeCount = paths.filter(function(p) { return !p.safe }).length
    const connectedDevices = devices.filter(function(d) { return d.connected }).length
    return {
      anchors: anchors.length,
      devices: devices.length,
      totalPaths: paths.length,
      activePaths: safeCount,
      unsafePaths: unsafeCount,
      totalDelivered: totalDelivered,
      avgEfficiency: avgEfficiency,
      connectedDevices: connectedDevices,
      safetyStatus: unsafeCount === 0 ? "GREEN" : unsafeCount < 3 ? "AMBER" : "RED",
    }
  }

  function setWalls(w) { walls = w }
  function setForbiddenZones(z) { forbiddenZones = z }
  function removeAnchor(id) {
    anchors = anchors.filter(function(a) { return a.id !== id })
    paths = paths.filter(function(p) { return p.src !== id && p.tgt !== id })
    logSafety("ANCHOR_REMOVED", id, "")
  }
  function removeDevice(id) {
    devices = devices.filter(function(d) { return d.id !== id })
    paths = paths.filter(function(p) { return p.tgt !== id })
    logSafety("DEVICE_REMOVED", id, "")
  }
  function moveAnchor(id, x, y) {
    const a = anchors.find(function(n) { return n.id === id })
    if (a) { a.x = x; a.y = y; recalcAllPaths() }
  }
  function moveDevice(id, x, y) {
    const d = devices.find(function(n) { return n.id === id })
    if (d) { d.x = x; d.y = y; recalcAllPaths() }
  }
  function toggleAnchor(id) {
    const a = anchors.find(function(n) { return n.id === id })
    if (a) {
      a.active = !a.active
      logSafety(a.active ? "ANCHOR_ACTIVATED" : "ANCHOR_DEACTIVATED", id, "")
      recalcAllPaths()
    }
  }

  function getTickCount() { return tickCount }
  function getExposure(id) { return exposureMap[id] || 0 }
  function getRooms() {
    const plan = currentPlan
    return plan && plan.rooms ? plan.rooms : []
  }

  let currentPlan = null
  function setCurrentPlan(plan) { currentPlan = plan }

  return {
    SAFETY: SAFETY,
    GEOMETRY_TYPES: GEOMETRY_TYPES,
    createAnchor: createAnchor,
    createDevice: createDevice,
    computePath: computePath,
    autoConnect: autoConnect,
    getDensityAt: getDensityAt,
    recalcAllPaths: recalcAllPaths,
    tick: tick,
    reset: reset,
    getAnchors: getAnchors,
    getDevices: getDevices,
    getPaths: getPaths,
    getWalls: getWalls,
    getForbiddenZones: getForbiddenZones,
    getSafetyLog: getSafetyLog,
    getMetrics: getMetrics,
    getTickCount: getTickCount,
    getExposure: getExposure,
    getRooms: getRooms,
    setCurrentPlan: setCurrentPlan,
    setWalls: setWalls,
    setForbiddenZones: setForbiddenZones,
    removeAnchor: removeAnchor,
    removeDevice: removeDevice,
    moveAnchor: moveAnchor,
    moveDevice: moveDevice,
    toggleAnchor: toggleAnchor,
  }
})()


