// ═══════════════════════════════════════════════════════════
// Lume Meridian — Prototype Canvas Renderer (Enhanced)
// 2D energy-path visualization with particles, room labels,
// range overlays, and ambient field effects
// ═══════════════════════════════════════════════════════════

const ProtoRenderer = (function() {
  let ctx = null
  let w = 0
  let h = 0
  let frameCount = 0
  let ambientParticles = []

  function init(canvas, width, height) {
    ctx = canvas
    w = width
    h = height
    frameCount = 0
    initAmbientParticles()
  }

  function initAmbientParticles() {
    ambientParticles = []
    for (let i = 0; i < 60; i++) {
      ambientParticles.push({
        x: math.random() * w,
        y: math.random() * h,
        vx: (math.random() - 0.5) * 0.3,
        vy: (math.random() - 0.5) * 0.3,
        r: math.random() * 1.5 + 0.3,
        alpha: math.random() * 0.15 + 0.02,
        pulse: math.random() * math.PI * 2,
      })
    }
  }

  // ── Draw full frame ──
  function drawFrame() {
    if (!ctx) return
    frameCount++
    ctx.clearRect(0, 0, w, h)
    drawGrid()
    drawAmbientField()
    drawWalls()
    drawRoomLabels()
    drawForbiddenZones()
    drawAnchorRanges()
    drawDensityOverlay()
    drawPaths()
    drawAnchors()
    drawDevices()
  }

  // ── Blueprint grid ──
  function drawGrid() {
    ctx.fillStyle = "rgba(6,182,212,0.015)"
    for (let gx = 0; gx < w; gx += 40) {
      for (let gy = 0; gy < h; gy += 40) {
        ctx.fillRect(gx, gy, 1, 1)
      }
    }
    ctx.strokeStyle = "rgba(6,182,212,0.03)"
    ctx.lineWidth = 0.5
    for (let gx = 0; gx < w; gx += 40) {
      ctx.beginPath(); ctx.moveTo(gx, 0); ctx.lineTo(gx, h); ctx.stroke()
    }
    for (let gy = 0; gy < h; gy += 40) {
      ctx.beginPath(); ctx.moveTo(0, gy); ctx.lineTo(w, gy); ctx.stroke()
    }
  }

  // ── Ambient floating particles ──
  function drawAmbientField() {
    ambientParticles.forEach(function(p) {
      p.x += p.vx
      p.y += p.vy
      p.pulse += 0.02
      if (p.x < 0) p.x = w
      if (p.x > w) p.x = 0
      if (p.y < 0) p.y = h
      if (p.y > h) p.y = 0
      const alpha = p.alpha * (0.6 + 0.4 * math.sin(p.pulse))
      ctx.beginPath()
      ctx.arc(p.x, p.y, p.r, 0, math.PI * 2)
      ctx.fillStyle = "rgba(6,182,212," + alpha + ")"
      ctx.fill()
    })
  }

  // ── Room labels ──
  function drawRoomLabels() {
    const rooms = MeridianEngine.getRooms()
    rooms.forEach(function(room) {
      // Subtle room background
      ctx.fillStyle = "rgba(6,182,212,0.012)"
      ctx.fillRect(room.x, room.y, room.w, room.h)
      // Room border (very subtle)
      ctx.strokeStyle = "rgba(6,182,212,0.04)"
      ctx.lineWidth = 0.5
      ctx.strokeRect(room.x, room.y, room.w, room.h)
      // Room label — pinned to top-left corner so nodes don't cover it
      ctx.font = "600 9px 'JetBrains Mono', monospace"
      ctx.fillStyle = "rgba(255,255,255,0.15)"
      ctx.textAlign = "left"
      ctx.fillText(room.name.toUpperCase(), room.x + 8, room.y + 16)
    })
  }

  // ── Walls ──
  function drawWalls() {
    const walls = MeridianEngine.getWalls()
    ctx.strokeStyle = "rgba(255,255,255,0.35)"
    ctx.lineWidth = 3
    ctx.lineCap = "round"
    walls.forEach(function(wall) {
      ctx.beginPath()
      ctx.moveTo(wall.x1, wall.y1)
      ctx.lineTo(wall.x2, wall.y2)
      ctx.stroke()
    })
    ctx.strokeStyle = "rgba(255,255,255,0.05)"
    ctx.lineWidth = 8
    walls.forEach(function(wall) {
      ctx.beginPath()
      ctx.moveTo(wall.x1, wall.y1)
      ctx.lineTo(wall.x2, wall.y2)
      ctx.stroke()
    })
  }

  // ── Forbidden zones ──
  function drawForbiddenZones() {
    const zones = MeridianEngine.getForbiddenZones()
    zones.forEach(function(z) {
      const pulse = 0.4 + 0.15 * math.sin(frameCount * 0.04)
      ctx.fillStyle = "rgba(244,63,94," + (pulse * 0.06) + ")"
      ctx.fillRect(z.x, z.y, z.w, z.h)
      ctx.strokeStyle = "rgba(244,63,94," + (pulse * 0.4) + ")"
      ctx.lineWidth = 1.5
      ctx.setLineDash([6, 4])
      ctx.strokeRect(z.x, z.y, z.w, z.h)
      ctx.setLineDash([])
      if (z.label) {
        ctx.font = "bold 9px 'JetBrains Mono', monospace"
        ctx.fillStyle = "rgba(244,63,94,0.5)"
        ctx.textAlign = "center"
        ctx.fillText(z.label.toUpperCase(), z.x + z.w / 2, z.y + z.h / 2 + 3)
      }
    })
  }

  // ── Anchor range circles ──
  function drawAnchorRanges() {
    const anchors = MeridianEngine.getAnchors()
    anchors.forEach(function(a) {
      if (!a.active) return
      const hex = a.data.color
      const rr = parseInt(hex.slice(1,3),16)
      const gg = parseInt(hex.slice(3,5),16)
      const bb = parseInt(hex.slice(5,7),16)
      const rgb = rr + "," + gg + "," + bb
      // Filled range circle
      const grad = ctx.createRadialGradient(a.x, a.y, 0, a.x, a.y, a.maxRange)
      grad.addColorStop(0, "rgba(" + rgb + ",0.03)")
      grad.addColorStop(0.7, "rgba(" + rgb + ",0.015)")
      grad.addColorStop(1, "rgba(" + rgb + ",0)")
      ctx.beginPath()
      ctx.arc(a.x, a.y, a.maxRange, 0, math.PI * 2)
      ctx.fillStyle = grad
      ctx.fill()
    })
  }

  // ── Density heat overlay ──
  function drawDensityOverlay() {
    const step = 30
    for (let x = 0; x < w; x += step) {
      for (let y = 0; y < h; y += step) {
        const density = MeridianEngine.getDensityAt(x + step/2, y + step/2)
        if (density > 5) {
          const ratio = math.min(1, density / MeridianEngine.SAFETY.MAX_DENSITY)
          if (ratio > 0.7) {
            ctx.fillStyle = "rgba(244,63,94," + (ratio * 0.08) + ")"
          } else if (ratio > 0.4) {
            ctx.fillStyle = "rgba(245,158,11," + (ratio * 0.06) + ")"
          } else {
            ctx.fillStyle = "rgba(6,182,212," + (ratio * 0.04) + ")"
          }
          ctx.fillRect(x, y, step, step)
        }
      }
    }
  }

  // ── Energy paths with enhanced particles ──
  function drawPaths() {
    const paths = MeridianEngine.getPaths()
    const anchors = MeridianEngine.getAnchors()
    const devices = MeridianEngine.getDevices()

    paths.forEach(function(p) {
      const src = anchors.find(function(a) { return a.id === p.src })
      const tgt = anchors.find(function(a) { return a.id === p.tgt }) ||
                   devices.find(function(d) { return d.id === p.tgt })
      if (!src || !tgt) return

      const pts = p.geometry.points
      const bw = p.geometry.beamWidth
      const color = !p.active ? "244,63,94" :
                     p.geometry.type === "curved" ? "168,85,247" :
                     p.geometry.type === "multinode" ? "251,191,36" :
                     p.geometry.type === "distributed" ? "34,197,94" :
                     p.geometry.type === "adaptive" ? "244,114,182" : "6,182,212"

      // Beam corridor glow
      if (p.active) {
        ctx.lineWidth = bw * 3
        ctx.strokeStyle = "rgba(" + color + ",0.03)"
        ctx.lineCap = "round"
        ctx.lineJoin = "round"
        ctx.beginPath()
        ctx.moveTo(pts[0].x, pts[0].y)
        for (let i = 1; i < pts.length; i++) { ctx.lineTo(pts[i].x, pts[i].y) }
        ctx.stroke()
      }

      // Beam width corridor
      ctx.lineWidth = bw
      ctx.strokeStyle = "rgba(" + color + "," + (p.active ? 0.06 : 0.03) + ")"
      ctx.beginPath()
      ctx.moveTo(pts[0].x, pts[0].y)
      for (let i = 1; i < pts.length; i++) { ctx.lineTo(pts[i].x, pts[i].y) }
      ctx.stroke()

      // Core beam line
      ctx.lineWidth = p.active ? 2 : 1
      ctx.strokeStyle = "rgba(" + color + "," + (p.active ? 0.7 : 0.3) + ")"
      if (!p.active) { ctx.setLineDash([4, 4]) }
      ctx.beginPath()
      ctx.moveTo(pts[0].x, pts[0].y)
      for (let i = 1; i < pts.length; i++) { ctx.lineTo(pts[i].x, pts[i].y) }
      ctx.stroke()
      ctx.setLineDash([])

      // Enhanced energy particles (8 per beam)
      if (p.active) {
        const particleColor = p.geometry.type === "curved" ? "168,85,247" :
                               p.geometry.type === "multinode" ? "251,191,36" :
                               p.geometry.type === "distributed" ? "34,197,94" :
                               p.geometry.type === "adaptive" ? "244,114,182" : "34,211,238"
        for (let pi = 0; pi < 8; pi++) {
          const t = ((frameCount * 1.5 + pi * 125) % 1000) / 1000
          const segIdx = math.floor(t * (pts.length - 1))
          const segT = (t * (pts.length - 1)) - segIdx
          if (segIdx >= pts.length - 1) return
          const px = pts[segIdx].x + (pts[segIdx+1].x - pts[segIdx].x) * segT
          const py = pts[segIdx].y + (pts[segIdx+1].y - pts[segIdx].y) * segT
          const alpha = 0.9 - math.abs(t - 0.5) * 1.4

          ctx.beginPath()
          ctx.arc(px, py, 8, 0, math.PI * 2)
          ctx.fillStyle = "rgba(" + particleColor + "," + math.max(0, alpha * 0.08) + ")"
          ctx.fill()
          ctx.beginPath()
          ctx.arc(px, py, 5, 0, math.PI * 2)
          ctx.fillStyle = "rgba(" + particleColor + "," + math.max(0, alpha * 0.15) + ")"
          ctx.fill()
          ctx.beginPath()
          ctx.arc(px, py, 2, 0, math.PI * 2)
          ctx.fillStyle = "rgba(" + particleColor + "," + math.max(0.1, alpha) + ")"
          ctx.fill()
        }
      }

      // Relay node markers for multi-node paths
      if (p.geometry.type === "multinode" && pts.length > 2) {
        for (let ri = 1; ri < pts.length - 1; ri++) {
          const rp = pts[ri]
          // Diamond shape relay marker
          ctx.save()
          ctx.translate(rp.x, rp.y)
          ctx.rotate(math.PI / 4)
          ctx.beginPath()
          ctx.rect(-5, -5, 10, 10)
          ctx.fillStyle = "rgba(251,191,36,0.3)"
          ctx.strokeStyle = "rgba(251,191,36,0.7)"
          ctx.lineWidth = 1.5
          ctx.fill()
          ctx.stroke()
          ctx.restore()
          // Relay label
          ctx.font = "bold 7px 'JetBrains Mono', monospace"
          ctx.textAlign = "center"
          ctx.fillStyle = "rgba(251,191,36,0.6)"
          ctx.fillText("R" + ri, rp.x, rp.y - 10)
        }
      }

      // Efficiency label at midpoint
      const midIdx = math.floor(pts.length / 2)
      const mx = pts[midIdx].x
      const my = pts[midIdx].y - 12
      ctx.font = "bold 9px 'JetBrains Mono', monospace"
      ctx.textAlign = "center"
      const labelColor = p.geometry.type === "curved" ? "rgba(168,85,247,0.5)" :
                          p.geometry.type === "multinode" ? "rgba(251,191,36,0.5)" :
                          p.geometry.type === "distributed" ? "rgba(34,197,94,0.5)" :
                          p.geometry.type === "adaptive" ? "rgba(244,114,182,0.5)" :
                          p.active ? "rgba(6,182,212,0.5)" : "rgba(244,63,94,0.4)"
      ctx.fillStyle = labelColor
      ctx.fillText(p.efficiency + "%", mx, my)
    })
  }

  // ── Anchor nodes ──
  function drawAnchors() {
    const anchors = MeridianEngine.getAnchors()
    anchors.forEach(function(a) {
      a.pulse += 0.03
      const r = a.cls === "D" ? 10 : a.cls === "C" ? 14 : a.cls === "B" ? 12 : 16
      const hex = a.data.color
      const rr = parseInt(hex.slice(1,3),16)
      const gg = parseInt(hex.slice(3,5),16)
      const bb = parseInt(hex.slice(5,7),16)
      const rgb = rr + "," + gg + "," + bb

      // Range ring
      if (a.active) {
        const rangeAlpha = 0.04 + 0.02 * math.sin(a.pulse)
        ctx.beginPath()
        ctx.arc(a.x, a.y, a.maxRange, 0, math.PI * 2)
        ctx.strokeStyle = "rgba(" + rgb + "," + rangeAlpha + ")"
        ctx.lineWidth = 1
        ctx.setLineDash([4, 8])
        ctx.stroke()
        ctx.setLineDash([])
      }

      // Outer glow
      const glowAlpha = a.active ? 0.12 + 0.06 * math.sin(a.pulse) : 0.03
      ctx.beginPath()
      ctx.arc(a.x, a.y, r + 14, 0, math.PI * 2)
      ctx.fillStyle = "rgba(" + rgb + "," + (glowAlpha * 0.4) + ")"
      ctx.fill()

      // Mid glow
      ctx.beginPath()
      ctx.arc(a.x, a.y, r + 6, 0, math.PI * 2)
      ctx.fillStyle = "rgba(" + rgb + "," + glowAlpha + ")"
      ctx.fill()

      // Node body
      ctx.beginPath()
      ctx.arc(a.x, a.y, r, 0, math.PI * 2)
      if (a.active) {
        const grad = ctx.createRadialGradient(a.x - 2, a.y - 2, 0, a.x, a.y, r)
        grad.addColorStop(0, "rgba(" + rgb + ",1)")
        grad.addColorStop(1, "rgba(" + rgb + ",0.7)")
        ctx.fillStyle = grad
      } else {
        ctx.fillStyle = "rgba(255,255,255,0.1)"
      }
      ctx.fill()

      // Inner highlight
      ctx.beginPath()
      ctx.arc(a.x - r * 0.2, a.y - r * 0.2, r * 0.35, 0, math.PI * 2)
      ctx.fillStyle = "rgba(255,255,255,0.15)"
      ctx.fill()

      // Label
      ctx.font = "bold 9px 'JetBrains Mono', monospace"
      ctx.fillStyle = "rgba(255,255,255,0.55)"
      ctx.textAlign = "center"
      ctx.fillText(a.id + " [" + a.cls + "]", a.x, a.y + r + 16)
      ctx.font = "500 8px 'Inter', sans-serif"
      ctx.fillStyle = "rgba(255,255,255,0.3)"
      ctx.fillText(a.label, a.x, a.y + r + 27)
    })
  }

  // ── Device icons ──
  function drawDevices() {
    const devices = MeridianEngine.getDevices()
    devices.forEach(function(d) {
      d.pulse += 0.04
      const r = 7
      const connected = d.connected
      const color = connected ? "34,211,238" : "255,255,255"
      const alpha = connected ? 0.9 : 0.3

      // Connection indicator ring
      if (connected) {
        const ringAlpha = 0.2 + 0.1 * math.sin(d.pulse)
        ctx.beginPath()
        ctx.arc(d.x, d.y, r + 8, 0, math.PI * 2)
        ctx.strokeStyle = "rgba(34,211,238," + ringAlpha + ")"
        ctx.lineWidth = 1
        ctx.stroke()
      }

      // Device body
      ctx.beginPath()
      ctx.arc(d.x, d.y, r, 0, math.PI * 2)
      ctx.fillStyle = "rgba(" + color + "," + alpha + ")"
      ctx.fill()

      // Device outline
      ctx.strokeStyle = "rgba(" + color + "," + (alpha * 0.5) + ")"
      ctx.lineWidth = 1.5
      ctx.stroke()

      // Power draw bar
      const drawRatio = d.draw / 100
      const barW = 20
      const barH = 3
      const barX = d.x - barW / 2
      const barY = d.y + r + 6
      ctx.fillStyle = "rgba(255,255,255,0.08)"
      ctx.fillRect(barX, barY, barW, barH)
      ctx.fillStyle = connected ? "rgba(34,211,238,0.6)" : "rgba(255,255,255,0.15)"
      ctx.fillRect(barX, barY, barW * drawRatio, barH)

      // Label
      ctx.font = "500 8px 'Inter', sans-serif"
      ctx.fillStyle = "rgba(255,255,255," + (connected ? 0.5 : 0.25) + ")"
      ctx.textAlign = "center"
      ctx.fillText(d.label, d.x, d.y + r + 20)
    })
  }

  return { init: init, drawFrame: drawFrame }
})()


// ═══════════════════════════════════════════════════════════
// Lume Meridian — Prototype Page (Enhanced)
// Interactive wireless-energy simulation dashboard with 2D/3D toggle
// ═══════════════════════════════════════════════════════════

const MeridianPrototype = (function() {
  let canvasEl = null
  let canvasCtx = null
  let canvasW = 0
  let canvasH = 0
  let animFrame = null
  let selectedItem = null
  let draggingItem = null
  let dragOffset = { x: 0, y: 0 }
  let toolMode = "select"
  let addAnchorClass = "A"
  let addDeviceProfile = "mobile"
  let selectedGeoType = "linear"
  let connectSource = null
  let activePreset = "home"
  let hudUpdateInterval = null
  let viewMode = "2d"
  let view3DInitialized = false
  let canvasWrapRef = null

  // ── Viewport (2D camera) ──
  let vpZoom = 1
  let vpPanX = 0
  let vpPanY = 0
  let isPanning = false
  let panStartX = 0
  let panStartY = 0
  let panStartVPX = 0
  let panStartVPY = 0

  // Convert screen coords to world coords
  function screenToWorld(sx, sy) {
    return { x: (sx - vpPanX) / vpZoom, y: (sy - vpPanY) / vpZoom }
  }

  // Auto-fit viewport to show entire plan
  function fitViewport(planW, planH) {
    const marginFrac = 0.9
    const scaleX = canvasW > 0 ? (canvasW * marginFrac) / planW : 1
    const scaleY = canvasH > 0 ? (canvasH * marginFrac) / planH : 1
    vpZoom = math.min(scaleX, scaleY, 1.5)
    vpPanX = (canvasW - planW * vpZoom) / 2
    vpPanY = (canvasH - planH * vpZoom) / 2
  }

  function render(container) {
    container.style.overflowY = "auto"
    container.style.minHeight = "calc(100vh - 60px)"

    const page = dom.create("div", { className: "mp-container" })

    // ════ LEFT SIDEBAR ════
    const sidebar = dom.create("div", { className: "mp-sidebar" })

    // Scenarios section
    const scenarioSection = dom.create("div", { className: "mp-section" })
    dom.add_child(scenarioSection, dom.create("div", { text: "DEPLOYMENT SCENARIO", className: "mp-section-title" }))
    const presets = [
      { id: "home", icon: "🏠" },
      { id: "office", icon: "🏢" },
      { id: "warehouse", icon: "🏭" },
      { id: "emergency", icon: "🚨" },
    ]
    presets.forEach(function(p) {
      const plan = FLOOR_PLANS[p.id]
      const btn = dom.create("button", {
        className: "mp-preset-btn" + (p.id === activePreset ? " active" : ""),
        html: p.icon + " " + plan.name + '<span class="mp-preset-desc">' + plan.desc + '</span>',
        attrs: { "data-preset": p.id },
        onClick: function() { loadPreset(p.id) }
      })
      dom.add_child(scenarioSection, btn)
    })
    dom.add_child(sidebar, scenarioSection)

    // View Mode Toggle
    const viewSection = dom.create("div", { className: "mp-section" })
    dom.add_child(viewSection, dom.create("div", { text: "VIEW MODE", className: "mp-section-title" }))
    const toggleWrap = dom.create("div", { className: "mp-view-toggle" })
    const btn2D = dom.create("button", {
      className: "mp-view-btn active",
      id: "mp-btn-2d",
      text: "◫ 2D BLUEPRINT",
      onClick: function() { switchView("2d") }
    })
    const btn3D = dom.create("button", {
      className: "mp-view-btn",
      id: "mp-btn-3d",
      text: "◰ 3D ISOMETRIC",
      onClick: function() { switchView("3d") }
    })
    dom.add_child(toggleWrap, btn2D)
    dom.add_child(toggleWrap, btn3D)
    dom.add_child(viewSection, toggleWrap)
    if (!Proto3DRenderer.isAvailable()) {
      dom.add_child(viewSection, dom.create("div", {
        text: "3D requires WebGL",
        styles: { fontSize: "9px", color: "rgba(255,255,255,0.2)", marginTop: "4px", textAlign: "center" }
      }))
    }
    dom.add_child(sidebar, viewSection)

    // Geometry type section
    const geoSection = dom.create("div", { className: "mp-section" })
    dom.add_child(geoSection, dom.create("div", { text: "BEAM GEOMETRY", className: "mp-section-title" }))
    const geoGrid = dom.create("div", { className: "mp-geo-grid" })
    const geoTypes = [
      { id: "linear", label: "Linear" },
      { id: "curved", label: "Curved" },
      { id: "multinode", label: "Multi" },
      { id: "distributed", label: "Distrib" },
      { id: "adaptive", label: "Adapt" },
    ]
    geoTypes.forEach(function(g) {
      const btn = dom.create("button", {
        className: "mp-geo-btn" + (g.id === selectedGeoType ? " active" : ""),
        text: g.label,
        attrs: { "data-geo": g.id },
        onClick: function() { selectGeoType(g.id) }
      })
      dom.add_child(geoGrid, btn)
    })
    dom.add_child(geoSection, geoGrid)
    dom.add_child(sidebar, geoSection)

    // Tools section
    const toolSection = dom.create("div", { className: "mp-section" })
    dom.add_child(toolSection, dom.create("div", { text: "TOOLS", className: "mp-section-title" }))
    const tools = [
      { label: "◆ Add Anchor [A]", action: function() { setToolMode("addAnchor"); addAnchorClass = "A" } },
      { label: "◇ Add Anchor [B]", action: function() { setToolMode("addAnchor"); addAnchorClass = "B" } },
      { label: "⬡ Add Anchor [C]", action: function() { setToolMode("addAnchor"); addAnchorClass = "C" } },
      { label: "· Add Micro [D]", action: function() { setToolMode("addAnchor"); addAnchorClass = "D" } },
    ]
    tools.forEach(function(t) {
      dom.add_child(toolSection, dom.create("button", { className: "mp-ctrl-btn", text: t.label, onClick: t.action }))
    })
    dom.add_child(toolSection, dom.create("div", { styles: { height: "6px" } }))
    const deviceTools = [
      { label: "📱 Add Mobile", profile: "mobile" },
      { label: "⌚ Add Wearable", profile: "wearable" },
      { label: "🏭 Add Industrial", profile: "industrial" },
      { label: "🚗 Add Vehicle", profile: "vehicle" },
      { label: "🚨 Add Emergency", profile: "emergency" },
    ]
    deviceTools.forEach(function(dt) {
      dom.add_child(toolSection, dom.create("button", {
        className: "mp-ctrl-btn", text: dt.label,
        onClick: function() { setToolMode("addDevice"); addDeviceProfile = dt.profile }
      }))
    })
    dom.add_child(sidebar, toolSection)

    // Actions section
    const actSection = dom.create("div", { className: "mp-section" })
    dom.add_child(actSection, dom.create("div", { text: "ACTIONS", className: "mp-section-title" }))
    dom.add_child(actSection, dom.create("button", {
      className: "mp-ctrl-btn", text: "⚡ Connect Nodes",
      onClick: function() { if (selectedItem) { setToolMode("connect"); connectSource = selectedItem } }
    }))
    dom.add_child(actSection, dom.create("button", {
      className: "mp-ctrl-btn", text: "🔗 Auto-Connect All",
      onClick: function() { MeridianEngine.autoConnect(); rebuildIfNeeded(); updateHUD() }
    }))
    dom.add_child(actSection, dom.create("button", {
      className: "mp-ctrl-btn", text: "⏻ Toggle Selected",
      onClick: function() { if (selectedItem) { MeridianEngine.toggleAnchor(selectedItem.id); rebuildIfNeeded(); updateHUD() } }
    }))
    dom.add_child(actSection, dom.create("button", {
      className: "mp-ctrl-btn mp-ctrl-btn-danger", text: "✕ Remove Selected",
      onClick: function() {
        if (selectedItem) {
          MeridianEngine.removeAnchor(selectedItem.id)
          MeridianEngine.removeDevice(selectedItem.id)
          selectedItem = null; rebuildIfNeeded(); updateHUD()
        }
      }
    }))
    dom.add_child(actSection, dom.create("button", {
      className: "mp-ctrl-btn mp-ctrl-btn-danger", text: "⌫ Reset All",
      onClick: function() { loadPreset(activePreset) }
    }))
    dom.add_child(sidebar, actSection)
    dom.add_child(page, sidebar)

    // ════ CANVAS AREA ════
    const canvasWrap = dom.create("div", { className: "mp-canvas-wrap", id: "mp-canvas-wrap" })
    canvasWrapRef = canvasWrap
    canvasEl = dom.create("canvas", { className: "mp-canvas", id: "mp-canvas" })
    canvasEl.addEventListener("contextmenu", function(e) { e.preventDefault() })
    canvasEl.addEventListener("mousedown", onMouseDown)
    canvasEl.addEventListener("mousemove", onMouseMove)
    canvasEl.addEventListener("mouseup", onMouseUp)
    canvasEl.addEventListener("mouseleave", onMouseUp)
    canvasEl.addEventListener("touchstart", onTouchStart, { passive: false })
    canvasEl.addEventListener("touchmove", onTouchMove, { passive: false })
    canvasEl.addEventListener("touchend", onTouchEnd)

    // Scroll-to-zoom
    canvasEl.addEventListener("wheel", function(e) {
      if (viewMode === "3d") return
      e.preventDefault()
      const rect = canvasEl.getBoundingClientRect()
      const mx = e.clientX - rect.left
      const my = e.clientY - rect.top
      const delta = e.deltaY > 0 ? 0.9 : 1.1
      const newZoom = math.max(0.15, math.min(5, vpZoom * delta))
      // Zoom towards cursor
      vpPanX = mx - (mx - vpPanX) * (newZoom / vpZoom)
      vpPanY = my - (my - vpPanY) * (newZoom / vpZoom)
      vpZoom = newZoom
    }, { passive: false })
    dom.add_child(canvasWrap, canvasEl)

    // 3D container (hidden initially)
    const canvas3DWrap = dom.create("div", { className: "mp-3d-container", id: "mp-3d-container", styles: { display: "none" } })
    dom.add_child(canvasWrap, canvas3DWrap)

    // Tool mode indicator
    const toolIndicator = dom.create("div", { className: "mp-tool-indicator", id: "mp-tool-mode", text: "SELECT MODE" })
    dom.add_child(canvasWrap, toolIndicator)

    // Status bar
    const statusBar = dom.create("div", { className: "mp-statusbar", id: "mp-statusbar" })
    const statusItems = [
      { id: "sb-power", label: "POWER", val: "0W" },
      { id: "sb-eff", label: "EFF", val: "0%" },
      { id: "sb-paths", label: "PATHS", val: "0" },
      { id: "sb-devices", label: "CONNECTED", val: "0/0" },
      { id: "sb-tick", label: "TICK", val: "0" },
    ]
    statusItems.forEach(function(si) {
      const item = dom.create("div", { className: "mp-status-item" })
      dom.add_child(item, dom.create("span", { text: si.label + ":" }))
      dom.add_child(item, dom.create("span", { className: "mp-status-val", id: si.id, text: si.val }))
      dom.add_child(statusBar, item)
    })
    dom.add_child(canvasWrap, statusBar)

    // ════ FULLSCREEN EXPAND BUTTON ════
    const fsExpandBtn = dom.create("button", { className: "mp-fs-expand-btn", attrs: { title: "Fullscreen 3D View" } })
    fsExpandBtn.innerHTML = "\u26f6"
    dom.add_child(canvasWrap, fsExpandBtn)

    // ════ FULLSCREEN MODAL ════
    const fsModal = dom.create("div", { className: "mp-fs-modal", id: "mp-fs-modal" })
    const fsCloseBtn = dom.create("button", { className: "mp-fs-close", id: "mp-fs-close" })
    fsCloseBtn.innerHTML = "\u2715"
    dom.add_child(fsModal, fsCloseBtn)
    const fsContent = dom.create("div", { className: "mp-fs-content", id: "mp-fs-content" })
    dom.add_child(fsModal, fsContent)

    let fsOrigParent = null
    let fsOrigCanvas = null
    let fsOrigNextSib = null
    let fsIs3DMode = false

    function openFullscreen() {
      if (viewMode === "2d") {
        fsOrigCanvas = canvasEl
      } else {
        const wrap3d = dom.select("#mp-3d-container")
        fsOrigCanvas = wrap3d ? wrap3d.querySelector("canvas") : null
      }
      if (!fsOrigCanvas) return
      fsIs3DMode = viewMode === "3d"
      fsOrigParent = fsOrigCanvas.parentElement
      fsOrigNextSib = fsOrigCanvas.nextSibling
      fsContent.appendChild(fsOrigCanvas)
      fsOrigCanvas.style.width = "100%"
      fsOrigCanvas.style.height = "100%"
      fsModal.classList.add("active")
      document.body.style.overflow = "hidden"
      // Trigger resize for Three.js or 2D canvas
      setTimeout(function() {
        if (fsIs3DMode) {
          const rect = fsContent.getBoundingClientRect()
          Proto3DRenderer.resize(rect.width, rect.height)
        } else {
          const rect = fsContent.getBoundingClientRect()
          const dpr = window.devicePixelRatio || 1
          fsOrigCanvas.width = rect.width * dpr
          fsOrigCanvas.height = rect.height * dpr
          fsOrigCanvas.style.width = rect.width + "px"
          fsOrigCanvas.style.height = rect.height + "px"
          canvasW = rect.width
          canvasH = rect.height
          canvasCtx = fsOrigCanvas.getContext("2d")
          canvasCtx.scale(dpr, dpr)
        }
      }, 50)
    }

    function closeFullscreen() {
      if (!fsOrigCanvas) return
      if (fsOrigNextSib) {
        fsOrigParent.insertBefore(fsOrigCanvas, fsOrigNextSib)
      } else {
        fsOrigParent.appendChild(fsOrigCanvas)
      }
      fsOrigCanvas.style.width = ""
      fsOrigCanvas.style.height = ""
      fsModal.classList.remove("active")
      document.body.style.overflow = ""
      // Restore size
      setTimeout(function() {
        if (fsIs3DMode) {
          const wrap = dom.select("#mp-canvas-wrap")
          if (wrap) {
            const rect = wrap.getBoundingClientRect()
            Proto3DRenderer.resize(rect.width, rect.height - 36)
          }
        } else {
          const wrap = dom.select("#mp-canvas-wrap")
          if (wrap) {
            const rect = wrap.getBoundingClientRect()
            const dpr = window.devicePixelRatio || 1
            canvasW = rect.width
            canvasH = rect.height - 36
            fsOrigCanvas.width = canvasW * dpr
            fsOrigCanvas.height = canvasH * dpr
            fsOrigCanvas.style.width = canvasW + "px"
            fsOrigCanvas.style.height = canvasH + "px"
            canvasCtx = fsOrigCanvas.getContext("2d")
            canvasCtx.scale(dpr, dpr)
          }
        }
      }, 50)
      fsOrigCanvas = null
      fsOrigParent = null
      fsOrigNextSib = null
    }

    fsExpandBtn.addEventListener("click", function(e) { e.stopPropagation(); openFullscreen() })
    fsCloseBtn.addEventListener("click", closeFullscreen)
    fsModal.addEventListener("click", function(e) { if (e.target === fsModal) closeFullscreen() })
    document.addEventListener("keydown", function(e) { if (e.key === "Escape" && fsModal.classList.contains("active")) closeFullscreen() })

    // Handle orientation changes in fullscreen
    window.addEventListener("orientationchange", function() {
      if (fsModal.classList.contains("active")) {
        setTimeout(function() {
          if (fsIs3DMode) {
            const rect = fsContent.getBoundingClientRect()
            Proto3DRenderer.resize(rect.width, rect.height)
          }
        }, 300)
      }
    })

    dom.add_child(page, canvasWrap)
    dom.add_child(document.body, fsModal)

    // ════ RIGHT SIDEBAR (HUD) ════
    const hudSidebar = dom.create("div", { className: "mp-sidebar-right" })

    // Safety status
    const safetySection = dom.create("div", { className: "mp-section" })
    dom.add_child(safetySection, dom.create("div", { text: "SAFETY ENVELOPE", className: "mp-section-title" }))
    dom.add_child(safetySection, dom.create("div", { className: "mp-safety mp-safety-green", id: "mp-safety-status", text: "ALL SAFE" }))
    dom.add_child(hudSidebar, safetySection)

    // Metrics HUD
    const metricsSection = dom.create("div", { className: "mp-section" })
    dom.add_child(metricsSection, dom.create("div", { text: "SYSTEM METRICS", className: "mp-section-title" }))
    const hudGrid = dom.create("div", { className: "mp-hud-grid" })
    const hudItems = [
      { id: "hud-anchors", label: "ANCHORS", val: "0", color: "#06b6d4" },
      { id: "hud-devices", label: "DEVICES", val: "0", color: "#22d3ee" },
      { id: "hud-active", label: "ACTIVE", val: "0", color: "#10b981" },
      { id: "hud-unsafe", label: "UNSAFE", val: "0", color: "#f43f5e" },
      { id: "hud-power", label: "WATTS", val: "0", color: "#14b8a6" },
      { id: "hud-eff", label: "EFFICIENCY", val: "0%", color: "#fbbf24" },
    ]
    hudItems.forEach(function(hi) {
      const cell = dom.create("div", { className: "mp-hud-cell" })
      dom.add_child(cell, dom.create("div", { className: "mp-hud-val", id: hi.id, text: hi.val, styles: { color: hi.color } }))
      dom.add_child(cell, dom.create("div", { className: "mp-hud-label", text: hi.label }))
      dom.add_child(hudGrid, cell)
    })
    dom.add_child(metricsSection, hudGrid)
    dom.add_child(hudSidebar, metricsSection)

    // Selected item detail
    const detailSection = dom.create("div", { className: "mp-section" })
    dom.add_child(detailSection, dom.create("div", { text: "SELECTED", className: "mp-section-title" }))
    dom.add_child(detailSection, dom.create("div", { id: "mp-detail", styles: { fontSize: "11px", color: "rgba(255,255,255,0.4)" } }))
    dom.add_child(hudSidebar, detailSection)

    // Audit log
    const logSection = dom.create("div", { className: "mp-section" })
    dom.add_child(logSection, dom.create("div", { text: "GOVERNANCE LOG", className: "mp-section-title" }))
    dom.add_child(logSection, dom.create("div", { className: "mp-log", id: "mp-log" }))
    dom.add_child(hudSidebar, logSection)

    dom.add_child(page, hudSidebar)
    dom.add_child(container, page)

    // Initialize canvas
    setTimeout(function() { initCanvas(canvasWrap); loadPreset("home") }, 50)
  }

  // ── View mode switch ──
  function switchView(mode) {
    if (mode === viewMode) return
    viewMode = mode

    const btn2D = dom.select("#mp-btn-2d")
    const btn3D = dom.select("#mp-btn-3d")
    const canvas2D = dom.select("#mp-canvas")
    const container3D = dom.select("#mp-3d-container")
    const toolMode = dom.select("#mp-tool-mode")

    if (mode === "3d") {
      if (btn2D) dom.remove_class(btn2D, "active")
      if (btn3D) dom.add_class(btn3D, "active")
      if (canvas2D) canvas2D.style.display = "none"
      if (container3D) container3D.style.display = "block"
      if (toolMode) toolMode.textContent = "3D ISOMETRIC VIEW"

      if (!view3DInitialized && Proto3DRenderer.isAvailable()) {
        const wrap = dom.select("#mp-canvas-wrap")
        if (wrap) {
          const rect = wrap.getBoundingClientRect()
          const w = rect.width
          const h = rect.height - 36
          const success = Proto3DRenderer.init(container3D, w, h)
          if (success) {
            view3DInitialized = true
            Proto3DRenderer.buildScene()
          }
        }
      } else if (view3DInitialized) {
        Proto3DRenderer.buildScene()
      }
    } else {
      if (btn2D) dom.add_class(btn2D, "active")
      if (btn3D) dom.remove_class(btn3D, "active")
      if (canvas2D) canvas2D.style.display = "block"
      if (container3D) container3D.style.display = "none"
      if (toolMode) toolMode.textContent = "SELECT MODE"
    }
  }

  function rebuildIfNeeded() {
    if (viewMode === "3d" && view3DInitialized) {
      Proto3DRenderer.buildScene()
    }
  }

  // ── Canvas init ──
  function initCanvas(wrap) {
    const rect = wrap.getBoundingClientRect()
    const dpr = window.devicePixelRatio || 1
    canvasW = rect.width
    canvasH = rect.height - 36
    canvasEl.width = canvasW * dpr
    canvasEl.height = canvasH * dpr
    canvasEl.style.width = canvasW + "px"
    canvasEl.style.height = canvasH + "px"
    canvasCtx = canvasEl.getContext("2d")
    canvasCtx.scale(dpr, dpr)
    ProtoRenderer.init(canvasCtx, canvasW, canvasH)
    startLoop()
  }

  // ── Animation loop ──
  function startLoop() {
    function frame() {
      MeridianEngine.tick()
      if (viewMode === "2d") {
        // Clear canvas in screen space first
        canvasCtx.clearRect(0, 0, canvasW, canvasH)
        // Apply viewport transform, then draw, then restore
        canvasCtx.save()
        canvasCtx.translate(vpPanX, vpPanY)
        canvasCtx.scale(vpZoom, vpZoom)
        ProtoRenderer.drawFrame()
        drawSelection()
        canvasCtx.restore()
      } else if (viewMode === "3d" && view3DInitialized) {
        Proto3DRenderer.animate()
      }
      animFrame = requestAnimationFrame(frame)
    }
    animFrame = requestAnimationFrame(frame)
    hudUpdateInterval = setInterval(updateHUD, 500)
  }

  function drawSelection() {
    if (!selectedItem || !canvasCtx) return
    canvasCtx.beginPath()
    const r = selectedItem.cls ? 20 : 12
    canvasCtx.arc(selectedItem.x, selectedItem.y, r, 0, math.PI * 2)
    canvasCtx.strokeStyle = "rgba(255,255,255,0.6)"
    canvasCtx.lineWidth = 2 / vpZoom
    canvasCtx.setLineDash([3, 3])
    canvasCtx.stroke()
    canvasCtx.setLineDash([])
  }

  // ── Load preset ──
  function loadPreset(id) {
    const plan = FLOOR_PLANS[id]
    if (!plan) return
    activePreset = id
    MeridianEngine.reset()
    MeridianEngine.setWalls(plan.walls)
    MeridianEngine.setForbiddenZones(plan.forbiddenZones || [])
    MeridianEngine.setCurrentPlan(plan)
    selectedItem = null; connectSource = null; setToolMode("select")

    plan.anchors.forEach(function(a) { MeridianEngine.createAnchor(a.x, a.y, a.cls, a.label) })
    plan.devices.forEach(function(d) { MeridianEngine.createDevice(d.x, d.y, d.profile) })
    MeridianEngine.autoConnect()

    // Auto-fit 2D viewport to plan dimensions
    fitViewport(plan.width || 800, plan.height || 500)

    // Update preset button states
    const allBtns = dom.select_all(".mp-preset-btn")
    allBtns.forEach(function(b) { dom.remove_class(b, "active") })
    const activeBtn = dom.select('.mp-preset-btn[data-preset="' + id + '"]')
    if (activeBtn) dom.add_class(activeBtn, "active")

    rebuildIfNeeded()
    updateHUD()
  }

  // ── Tool mode ──
  function setToolMode(mode) {
    toolMode = mode
    const indicator = dom.select("#mp-tool-mode")
    if (!indicator) return
    if (viewMode === "3d") {
      indicator.textContent = "3D ISOMETRIC VIEW"
      return
    }
    const labels = { select: "SELECT MODE", addAnchor: "PLACE ANCHOR [" + addAnchorClass + "]", addDevice: "PLACE DEVICE", connect: "CONNECT → SELECT TARGET" }
    indicator.textContent = labels[mode] || mode.toUpperCase()
  }

  function selectGeoType(type) {
    selectedGeoType = type
    const allBtns = dom.select_all(".mp-geo-btn")
    allBtns.forEach(function(b) { dom.remove_class(b, "active") })
    const activeBtn = dom.select('.mp-geo-btn[data-geo="' + type + '"]')
    if (activeBtn) dom.add_class(activeBtn, "active")
    MeridianEngine.recalcAllPaths(type)
    rebuildIfNeeded()
  }

  // ── Mouse handlers ──
  function getItemAt(x, y) {
    const anchors = MeridianEngine.getAnchors()
    const devices = MeridianEngine.getDevices()
    for (let i = anchors.length - 1; i >= 0; i--) {
      const a = anchors[i]
      const dx = x - a.x
      const dy = y - a.y
      if (dx*dx + dy*dy < 400) return a
    }
    for (let i = devices.length - 1; i >= 0; i--) {
      const d = devices[i]
      const dx = x - d.x
      const dy = y - d.y
      if (dx*dx + dy*dy < 200) return d
    }
    return null
  }

  function onMouseDown(e) {
    if (viewMode === "3d") return
    const rect = canvasEl.getBoundingClientRect()
    const sx = e.clientX - rect.left
    const sy = e.clientY - rect.top
    const world = screenToWorld(sx, sy)
    const x = world.x
    const y = world.y

    // Right-click or middle-click = pan
    if (e.button === 1 || e.button === 2) {
      isPanning = true
      panStartX = e.clientX; panStartY = e.clientY
      panStartVPX = vpPanX; panStartVPY = vpPanY
      e.preventDefault()
      return
    }

    if (toolMode === "addAnchor") {
      MeridianEngine.createAnchor(x, y, addAnchorClass)
      MeridianEngine.autoConnect()
      setToolMode("select"); rebuildIfNeeded(); updateHUD(); return
    }
    if (toolMode === "addDevice") {
      MeridianEngine.createDevice(x, y, addDeviceProfile)
      MeridianEngine.autoConnect()
      setToolMode("select"); rebuildIfNeeded(); updateHUD(); return
    }
    if (toolMode === "connect") {
      const hit = getItemAt(x, y)
      if (hit && connectSource && hit.id !== connectSource.id) {
        MeridianEngine.computePath(connectSource.id, hit.id, selectedGeoType)
        connectSource = null; setToolMode("select"); rebuildIfNeeded(); updateHUD()
      }
      return
    }

    const hit = getItemAt(x, y)
    if (hit) {
      selectedItem = hit
      draggingItem = hit
      dragOffset.x = x - hit.x
      dragOffset.y = y - hit.y
      updateHUD()
    } else {
      // No item hit — start panning
      isPanning = true
      panStartX = e.clientX; panStartY = e.clientY
      panStartVPX = vpPanX; panStartVPY = vpPanY
      selectedItem = null
      updateHUD()
    }
  }

  function onMouseMove(e) {
    if (viewMode === "3d") return
    if (isPanning) {
      vpPanX = panStartVPX + (e.clientX - panStartX)
      vpPanY = panStartVPY + (e.clientY - panStartY)
      return
    }
    if (!draggingItem) return
    const rect = canvasEl.getBoundingClientRect()
    const world = screenToWorld(e.clientX - rect.left, e.clientY - rect.top)
    const x = world.x - dragOffset.x
    const y = world.y - dragOffset.y
    if (draggingItem.cls !== undefined) { MeridianEngine.moveAnchor(draggingItem.id, x, y) }
    else { MeridianEngine.moveDevice(draggingItem.id, x, y) }
  }

  function onMouseUp() {
    if (isPanning) { isPanning = false; return }
    if (draggingItem) { rebuildIfNeeded() }
    draggingItem = null
  }

  // ── Touch handlers with pinch-to-zoom ──
  let lastPinchDist = 0
  let lastTouchMid = { x: 0, y: 0 }

  function onTouchStart(e) {
    e.preventDefault()
    if (e.touches.length === 2) {
      // Pinch start
      const dx = e.touches[0].clientX - e.touches[1].clientX
      const dy = e.touches[0].clientY - e.touches[1].clientY
      lastPinchDist = math.sqrt(dx * dx + dy * dy)
      lastTouchMid = { x: (e.touches[0].clientX + e.touches[1].clientX) / 2, y: (e.touches[0].clientY + e.touches[1].clientY) / 2 }
      isPanning = true
      panStartX = lastTouchMid.x; panStartY = lastTouchMid.y
      panStartVPX = vpPanX; panStartVPY = vpPanY
    } else if (e.touches.length === 1) {
      const tc = e.touches[0]
      onMouseDown({ clientX: tc.clientX, clientY: tc.clientY, button: 0, preventDefault: function() {} })
    }
  }

  function onTouchMove(e) {
    e.preventDefault()
    if (e.touches.length === 2) {
      const dx = e.touches[0].clientX - e.touches[1].clientX
      const dy = e.touches[0].clientY - e.touches[1].clientY
      const dist = math.sqrt(dx * dx + dy * dy)
      const mid = { x: (e.touches[0].clientX + e.touches[1].clientX) / 2, y: (e.touches[1].clientY + e.touches[0].clientY) / 2 }
      const rect = canvasEl.getBoundingClientRect()
      const mx = mid.x - rect.left
      const my = mid.y - rect.top
      if (lastPinchDist > 0) {
        const scale = dist / lastPinchDist
        const newZoom = math.max(0.15, math.min(5, vpZoom * scale))
        vpPanX = mx - (mx - vpPanX) * (newZoom / vpZoom)
        vpPanY = my - (my - vpPanY) * (newZoom / vpZoom)
        vpZoom = newZoom
      }
      // Also pan
      vpPanX = panStartVPX + (mid.x - panStartX)
      vpPanY = panStartVPY + (mid.y - panStartY)
      panStartX = mid.x; panStartY = mid.y
      panStartVPX = vpPanX; panStartVPY = vpPanY
      lastPinchDist = dist
    } else if (e.touches.length === 1) {
      const tc = e.touches[0]
      onMouseMove({ clientX: tc.clientX, clientY: tc.clientY })
    }
  }

  function onTouchEnd(e) {
    lastPinchDist = 0
    isPanning = false
    onMouseUp()
  }

  // ── HUD Update ──
  function updateHUD() {
    const m = MeridianEngine.getMetrics()
    dom.set_text("#hud-anchors", String(m.anchors))
    dom.set_text("#hud-devices", String(m.devices))
    dom.set_text("#hud-active", String(m.activePaths))
    dom.set_text("#hud-unsafe", String(m.unsafePaths))
    dom.set_text("#hud-power", m.totalDelivered + "W")
    dom.set_text("#hud-eff", m.avgEfficiency + "%")

    // Status bar
    dom.set_text("#sb-power", m.totalDelivered + "W")
    dom.set_text("#sb-eff", m.avgEfficiency + "%")
    dom.set_text("#sb-paths", String(m.activePaths))
    dom.set_text("#sb-devices", m.connectedDevices + "/" + m.devices)
    dom.set_text("#sb-tick", String(MeridianEngine.getTickCount()))

    // Safety status
    const safetyEl = dom.select("#mp-safety-status")
    if (safetyEl) {
      safetyEl.className = "mp-safety mp-safety-" + m.safetyStatus.toLowerCase()
      safetyEl.textContent = m.safetyStatus === "GREEN" ? "ALL SAFE" : m.safetyStatus === "AMBER" ? "WARNING" : "VIOLATION"
    }

    // Detail panel
    const detailEl = dom.select("#mp-detail")
    if (detailEl && selectedItem) {
      const s = selectedItem
      if (s.cls !== undefined) {
        const exposure = MeridianEngine.getExposure(s.id)
        dom.set_html(detailEl, '<div style="color:#06b6d4;font-weight:700;margin-bottom:4px">' + s.id + ' — ' + s.data.name + '</div>' +
          '<div>Class: ' + s.cls + ' | Power: ' + s.maxPower + 'W</div>' +
          '<div>Range: ' + s.maxRange + 'px | ' + (s.active ? '<span style="color:#10b981">ACTIVE</span>' : '<span style="color:#f43f5e">INACTIVE</span>') + '</div>')
      } else {
        const exposure = MeridianEngine.getExposure(s.id)
        const expSec = math.round(exposure / 1000)
        dom.set_html(detailEl, '<div style="color:#22d3ee;font-weight:700;margin-bottom:4px">' + s.id + ' — ' + s.label + '</div>' +
          '<div>Draw: ' + s.draw + 'W | Priority: ' + s.priority + '</div>' +
          '<div>Exposure: ' + expSec + 's / ' + (MeridianEngine.SAFETY.MAX_EXPOSURE_MS / 1000) + 's</div>' +
          '<div>' + (s.connected ? '<span style="color:#10b981">CONNECTED → ' + s.connectedAnchor + '</span>' : '<span style="color:#f43f5e">DISCONNECTED</span>') + '</div>')
      }
    } else if (detailEl) {
      dom.set_html(detailEl, '<span style="color:rgba(255,255,255,0.25)">Click a node to inspect</span>')
    }

    // Audit log
    const logEl = dom.select("#mp-log")
    if (logEl) {
      const log = MeridianEngine.getSafetyLog()
      const recent = log.slice(-15).reverse()
      const html = ""
      recent.forEach(function(entry) {
        const typeClass = entry.type.includes("BLOCK") || entry.type.includes("VIOLATION") || entry.type.includes("COLLAPSE") || entry.type.includes("EXPOSURE") ? "danger" :
                           entry.type.includes("DEACTIVAT") || entry.type.includes("REMOVE") ? "warn" :
                           entry.type.includes("ACTIVE") || entry.type.includes("CREATED") ? "safe" : "info"
        html += '<div class="mp-log-entry"><span class="mp-log-type mp-log-type-' + typeClass + '">' + entry.type + '</span> ' + entry.target + ' ' + entry.message + '</div>'
      })
      logEl.innerHTML = html
      logEl.scrollTop = 0
    }
  }

  return { render: render }
})()

MeridianRouter.register("prototype", MeridianPrototype.render)


// ═══════════════════════════════════════════════════════════
// Lume Meridian — 3D Prototype Renderer (Three.js)
// Isometric building visualization with energy beams
// ═══════════════════════════════════════════════════════════

const Proto3DRenderer = (function() {
  let scene = null
  let camera = null
  let renderer = null
  let controls = null
  let container = null
  let animFrame = null
  let frameCount = 0
  let meshGroups = { anchors: [], devices: [], beams: [], walls: [], zones: [], labels: [], floor: null, ceiling: null }
  let particleSystems = []
  let anchorLights = []

  const SCALE = 0.5
  const WALL_HEIGHT = 50
  const CEILING_Y = WALL_HEIGHT
  const ANCHOR_Y = WALL_HEIGHT - 6
  const DEVICE_Y = 3

  function sx(v) { return v * SCALE }
  function sz(v) { return v * SCALE }

  function init(containerEl, width, height) {
    if (typeof THREE === "undefined") return false
    container = containerEl

    // Scene
    scene = new THREE.Scene()
    scene.background = new THREE.Color(0x030310)

    // Camera — close and angled for dramatic view
    camera = new THREE.PerspectiveCamera(55, width / height, 1, 2000)
    camera.position.set(sx(500), 200, sz(500))
    camera.lookAt(sx(400), 0, sz(250))

    // Renderer
    renderer = new THREE.WebGLRenderer({ antialias: true, alpha: false })
    renderer.setSize(width, height)
    renderer.setPixelRatio(math.min(window.devicePixelRatio, 2))
    renderer.toneMapping = THREE.ACESFilmicToneMapping
    renderer.toneMappingExposure = 1.8
    containerEl.appendChild(renderer.domElement)
    renderer.domElement.style.width = "100%"
    renderer.domElement.style.height = "100%"
    renderer.domElement.style.display = "block"

    // Controls
    controls = new THREE.OrbitControls(camera, renderer.domElement)
    controls.target.set(sx(400), 10, sz(250))
    controls.enableDamping = true
    controls.dampingFactor = 0.08
    controls.maxPolarAngle = math.PI / 2.05
    controls.minDistance = 80
    controls.maxDistance = 800
    controls.update()

    // ══ LIGHTING — bright enough to actually see ══

    // Strong ambient
    const ambient = new THREE.AmbientLight(0x1a2a40, 1.5)
    scene.add(ambient)

    // Hemisphere light for natural fill
    const hemi = new THREE.HemisphereLight(0x06b6d4, 0x0a0a20, 0.8)
    scene.add(hemi)

    // Main directional — key light
    const dirLight = new THREE.DirectionalLight(0xffffff, 0.6)
    dirLight.position.set(sx(600), 300, sz(-100))
    scene.add(dirLight)

    // Secondary fill light
    const fillLight = new THREE.DirectionalLight(0x06b6d4, 0.4)
    fillLight.position.set(sx(-200), 200, sz(400))
    scene.add(fillLight)

    // Overhead point light
    const overheadLight = new THREE.PointLight(0x14b8a6, 0.5, 600)
    overheadLight.position.set(sx(400), 120, sz(250))
    scene.add(overheadLight)

    // Build static elements
    buildFloor()

    return true
  }

  function buildFloor() {
    // Main floor
    const floorGeo = new THREE.PlaneGeometry(sx(1000), sz(600))
    const floorMat = new THREE.MeshPhongMaterial({
      color: 0x0c0c1e,
      shininess: 60,
      specular: 0x111133,
    })
    const floor = new THREE.Mesh(floorGeo, floorMat)
    floor.rotation.x = -math.PI / 2
    floor.position.set(sx(500), 0, sz(300))
    floor.receiveShadow = true
    scene.add(floor)
    meshGroups.floor = floor

    // Floor grid lines
    const gridMat = new THREE.LineBasicMaterial({ color: 0x06b6d4, transparent: true, opacity: 0.08 })
    for (let x = 0; x <= 1000; x += 40) {
      const pts = [new THREE.Vector3(sx(x), 0.2, sz(0)), new THREE.Vector3(sx(x), 0.2, sz(600))]
      const geo = new THREE.BufferGeometry().setFromPoints(pts)
      scene.add(new THREE.Line(geo, gridMat))
    }
    for (let z = 0; z <= 600; z += 40) {
      const pts = [new THREE.Vector3(sx(0), 0.2, sz(z)), new THREE.Vector3(sx(1000), 0.2, sz(z))]
      const geo = new THREE.BufferGeometry().setFromPoints(pts)
      scene.add(new THREE.Line(geo, gridMat))
    }
  }

  // ── Sprite label helper ──
  function makeLabel(text, color, size) {
    const canvas2 = document.createElement("canvas")
    const labelSize = size || 256
    canvas2.width = labelSize
    canvas2.height = 64
    const c = canvas2.getContext("2d")
    c.fillStyle = "transparent"
    c.fillRect(0, 0, labelSize, 64)
    c.font = "bold 22px 'JetBrains Mono', monospace"
    c.textAlign = "center"
    c.fillStyle = color || "rgba(255,255,255,0.7)"
    c.fillText(text, labelSize / 2, 38)
    const tex = new THREE.CanvasTexture(canvas2)
    const spriteMat = new THREE.SpriteMaterial({ map: tex, transparent: true, depthWrite: false })
    const sprite = new THREE.Sprite(spriteMat)
    sprite.scale.set(labelSize / 8, 8, 1)
    return sprite
  }

  function buildScene() {
    clearDynamic()
    buildWalls3D()
    buildForbiddenZones3D()
    buildAnchors3D()
    buildDevices3D()
    buildBeams3D()
    buildRoomLabels3D()
    buildCeiling()
  }

  function buildRoomLabels3D() {
    const rooms = MeridianEngine.getRooms()
    rooms.forEach(function(rm) {
      const label = makeLabel(rm.name.toUpperCase(), "rgba(6,182,212,0.35)", 512)
      label.position.set(sx(rm.x + rm.w / 2), 2, sz(rm.y + rm.h / 2))
      label.scale.set(rm.w * SCALE * 0.6, 8, 1)
      scene.add(label)
      meshGroups.labels.push(label)
    })
  }

  function clearDynamic() {
    const keys = ["anchors", "devices", "beams", "walls", "zones", "labels"]
    keys.forEach(function(key) {
      if (Array.isArray(meshGroups[key])) {
        meshGroups[key].forEach(function(m) { scene.remove(m) })
        meshGroups[key] = []
      }
    })
    if (meshGroups.ceiling) { scene.remove(meshGroups.ceiling); meshGroups.ceiling = null }
    particleSystems.forEach(function(ps) { scene.remove(ps.mesh) })
    particleSystems = []
    anchorLights.forEach(function(l) { scene.remove(l) })
    anchorLights = []
  }

  function buildCeiling() {
    const ceilGeo = new THREE.PlaneGeometry(sx(1000), sz(600))
    const ceilMat = new THREE.MeshPhongMaterial({
      color: 0x0a0a18,
      transparent: true,
      opacity: 0.15,
      side: THREE.DoubleSide,
    })
    const ceil = new THREE.Mesh(ceilGeo, ceilMat)
    ceil.rotation.x = math.PI / 2
    ceil.position.set(sx(500), CEILING_Y, sz(300))
    scene.add(ceil)
    meshGroups.ceiling = ceil
  }

  function buildWalls3D() {
    const walls = MeridianEngine.getWalls()

    walls.forEach(function(wall) {
      const dx = sx(wall.x2) - sx(wall.x1)
      const dz = sz(wall.y2) - sz(wall.y1)
      const len = math.sqrt(dx * dx + dz * dz)
      if (len < 1) return
      const angle = math.atan2(dz, dx)

      // Solid wall
      const wallGeo = new THREE.BoxGeometry(len, WALL_HEIGHT, 3)
      const wallMat = new THREE.MeshPhongMaterial({
        color: 0x1e2040,
        transparent: true,
        opacity: 0.7,
        shininess: 20,
        specular: 0x222244,
      })
      const wallMesh = new THREE.Mesh(wallGeo, wallMat)
      wallMesh.position.set(
        (sx(wall.x1) + sx(wall.x2)) / 2,
        WALL_HEIGHT / 2,
        (sz(wall.y1) + sz(wall.y2)) / 2
      )
      wallMesh.rotation.y = -angle
      scene.add(wallMesh)
      meshGroups.walls.push(wallMesh)

      // Glowing edge wireframe
      const edges = new THREE.EdgesGeometry(wallGeo)
      const edgeMat = new THREE.LineBasicMaterial({ color: 0x06b6d4, transparent: true, opacity: 0.25 })
      const edgeLine = new THREE.LineSegments(edges, edgeMat)
      edgeLine.position.copy(wallMesh.position)
      edgeLine.rotation.copy(wallMesh.rotation)
      scene.add(edgeLine)
      meshGroups.walls.push(edgeLine)

      // Top edge glow line
      const topGeo = new THREE.BufferGeometry().setFromPoints([
        new THREE.Vector3(-len/2, WALL_HEIGHT/2, 0),
        new THREE.Vector3(len/2, WALL_HEIGHT/2, 0),
      ])
      const topMat = new THREE.LineBasicMaterial({ color: 0x22d3ee, transparent: true, opacity: 0.4 })
      const topLine = new THREE.Line(topGeo, topMat)
      topLine.position.copy(wallMesh.position)
      topLine.rotation.copy(wallMesh.rotation)
      scene.add(topLine)
      meshGroups.walls.push(topLine)
    })
  }

  function buildForbiddenZones3D() {
    const zones = MeridianEngine.getForbiddenZones()
    zones.forEach(function(z) {
      const zoneGeo = new THREE.BoxGeometry(sx(z.w), WALL_HEIGHT * 0.6, sz(z.h))
      const zoneMat = new THREE.MeshPhongMaterial({
        color: 0xf43f5e,
        transparent: true,
        opacity: 0.1,
        emissive: 0xf43f5e,
        emissiveIntensity: 0.3,
      })
      const zoneMesh = new THREE.Mesh(zoneGeo, zoneMat)
      zoneMesh.position.set(sx(z.x + z.w / 2), WALL_HEIGHT * 0.3, sz(z.y + z.h / 2))
      scene.add(zoneMesh)
      meshGroups.zones.push(zoneMesh)

      // Red edge wireframe
      const edges = new THREE.EdgesGeometry(zoneGeo)
      const edgeMat = new THREE.LineBasicMaterial({ color: 0xf43f5e, transparent: true, opacity: 0.5 })
      const edgeLine = new THREE.LineSegments(edges, edgeMat)
      edgeLine.position.copy(zoneMesh.position)
      scene.add(edgeLine)
      meshGroups.zones.push(edgeLine)
    })
  }

  function buildAnchors3D() {
    const anchors = MeridianEngine.getAnchors()
    anchors.forEach(function(a) {
      const hex = a.data.color
      const colorInt = parseInt(hex.slice(1), 16)
      const r = a.cls === "D" ? 3 : a.cls === "C" ? 5 : a.cls === "B" ? 4 : 6

      // Main anchor sphere
      const sphereGeo = new THREE.SphereGeometry(r, 20, 16)
      const sphereMat = new THREE.MeshPhongMaterial({
        color: colorInt,
        emissive: colorInt,
        emissiveIntensity: a.active ? 0.8 : 0.1,
        shininess: 100,
        specular: 0xffffff,
      })
      const sphere = new THREE.Mesh(sphereGeo, sphereMat)
      sphere.position.set(sx(a.x), ANCHOR_Y, sz(a.y))
      scene.add(sphere)
      sphere.userData = { type: "anchor", ref: a }
      meshGroups.anchors.push(sphere)

      // Anchor label
      const aLabel = makeLabel(a.id + " [" + a.cls + "]", a.data.color)
      aLabel.position.set(sx(a.x), ANCHOR_Y + 10, sz(a.y))
      scene.add(aLabel)
      meshGroups.labels.push(aLabel)
      const aNameLabel = makeLabel(a.label, "rgba(255,255,255,0.4)")
      aNameLabel.position.set(sx(a.x), ANCHOR_Y + 5, sz(a.y))
      aNameLabel.scale.set(24, 6, 1)
      scene.add(aNameLabel)
      meshGroups.labels.push(aNameLabel)

      // Outer glow sphere
      const glowGeo = new THREE.SphereGeometry(r * 2, 16, 12)
      const glowMat = new THREE.MeshBasicMaterial({
        color: colorInt,
        transparent: true,
        opacity: a.active ? 0.12 : 0.02,
      })
      const glow = new THREE.Mesh(glowGeo, glowMat)
      glow.position.copy(sphere.position)
      scene.add(glow)
      meshGroups.anchors.push(glow)

      // Mount rod from ceiling
      const poleGeo = new THREE.CylinderGeometry(0.8, 0.8, 6, 6)
      const poleMat = new THREE.MeshPhongMaterial({ color: 0x444466, emissive: colorInt, emissiveIntensity: 0.1 })
      const pole = new THREE.Mesh(poleGeo, poleMat)
      pole.position.set(sx(a.x), CEILING_Y - 3, sz(a.y))
      scene.add(pole)
      meshGroups.anchors.push(pole)

      if (a.active) {
        // Downward light cone
        const coneGeo = new THREE.ConeGeometry(r * 4, 30, 12, 1, true)
        const coneMat = new THREE.MeshBasicMaterial({
          color: colorInt,
          transparent: true,
          opacity: 0.06,
          side: THREE.DoubleSide,
        })
        const cone = new THREE.Mesh(coneGeo, coneMat)
        cone.position.set(sx(a.x), ANCHOR_Y - 18, sz(a.y))
        scene.add(cone)
        meshGroups.anchors.push(cone)

        // Point light per anchor
        const aLight = new THREE.PointLight(colorInt, 0.6, sx(a.maxRange) * 0.6)
        aLight.position.set(sx(a.x), ANCHOR_Y - 5, sz(a.y))
        scene.add(aLight)
        anchorLights.push(aLight)

        // Range circle on floor
        const rangeGeo = new THREE.RingGeometry(sx(a.maxRange) - 1, sx(a.maxRange), 48)
        const rangeMat = new THREE.MeshBasicMaterial({
          color: colorInt,
          transparent: true,
          opacity: 0.08,
          side: THREE.DoubleSide,
        })
        const rangeRing = new THREE.Mesh(rangeGeo, rangeMat)
        rangeRing.rotation.x = -math.PI / 2
        rangeRing.position.set(sx(a.x), 0.5, sz(a.y))
        scene.add(rangeRing)
        meshGroups.anchors.push(rangeRing)
      }
    })
  }

  function buildDevices3D() {
    const devices = MeridianEngine.getDevices()
    devices.forEach(function(d) {
      const connected = d.connected
      const colorInt = connected ? 0x22d3ee : 0x555566

      // Device body
      const boxGeo = new THREE.BoxGeometry(5, 3, 5)
      const boxMat = new THREE.MeshPhongMaterial({
        color: colorInt,
        emissive: connected ? 0x22d3ee : 0x111122,
        emissiveIntensity: connected ? 0.5 : 0.05,
        shininess: 80,
        specular: 0xffffff,
      })
      const box = new THREE.Mesh(boxGeo, boxMat)
      box.position.set(sx(d.x), DEVICE_Y, sz(d.y))
      scene.add(box)
      box.userData = { type: "device", ref: d }
      meshGroups.devices.push(box)

      // Device label
      const dLabel = makeLabel(d.label, connected ? "rgba(34,211,238,0.7)" : "rgba(255,255,255,0.3)")
      dLabel.position.set(sx(d.x), DEVICE_Y + 10, sz(d.y))
      dLabel.scale.set(24, 6, 1)
      scene.add(dLabel)
      meshGroups.labels.push(dLabel)

      if (connected) {
        // Connection ring on floor
        const ringGeo = new THREE.RingGeometry(4, 5, 16)
        const ringMat = new THREE.MeshBasicMaterial({
          color: 0x22d3ee,
          transparent: true,
          opacity: 0.2,
          side: THREE.DoubleSide,
        })
        const ring = new THREE.Mesh(ringGeo, ringMat)
        ring.rotation.x = -math.PI / 2
        ring.position.set(sx(d.x), 0.5, sz(d.y))
        scene.add(ring)
        meshGroups.devices.push(ring)

        // Upward glow
        const glowGeo = new THREE.SphereGeometry(4, 8, 6)
        const glowMat = new THREE.MeshBasicMaterial({
          color: 0x22d3ee,
          transparent: true,
          opacity: 0.08,
        })
        const glowSphere = new THREE.Mesh(glowGeo, glowMat)
        glowSphere.position.set(sx(d.x), DEVICE_Y + 2, sz(d.y))
        scene.add(glowSphere)
        meshGroups.devices.push(glowSphere)
      }
    })
  }

  function buildBeams3D() {
    const paths = MeridianEngine.getPaths()
    const anchors = MeridianEngine.getAnchors()
    const devices = MeridianEngine.getDevices()

    paths.forEach(function(p) {
      const src = anchors.find(function(a) { return a.id === p.src })
      const tgt = anchors.find(function(a) { return a.id === p.tgt }) ||
                   devices.find(function(d) { return d.id === p.tgt })
      if (!src || !tgt) return

      const isDevice = tgt.draw !== undefined
      const geoType = p.geometry.type || "linear"

      const beamColor = !p.active ? 0xf43f5e :
                         geoType === "curved" ? 0xa855f7 :
                         geoType === "multinode" ? 0xfbbf24 :
                         geoType === "distributed" ? 0x22c55e :
                         geoType === "adaptive" ? 0xf472b6 : 0x06b6d4
      const glowColor = !p.active ? 0xfb7185 :
                         geoType === "curved" ? 0xc084fc :
                         geoType === "multinode" ? 0xfcd34d :
                         geoType === "distributed" ? 0x4ade80 :
                         geoType === "adaptive" ? 0xf9a8d4 : 0x22d3ee

      const pts2d = p.geometry.points
      let waypoints = []

      if (isDevice) {
        waypoints.push(new THREE.Vector3(sx(src.x), ANCHOR_Y, sz(src.y)))
        waypoints.push(new THREE.Vector3(sx(src.x), CEILING_Y - 2, sz(src.y)))
        for (let gi = 1; gi < pts2d.length - 1; gi++) {
          waypoints.push(new THREE.Vector3(sx(pts2d[gi].x), CEILING_Y - 2, sz(pts2d[gi].y)))
        }
        waypoints.push(new THREE.Vector3(sx(tgt.x), CEILING_Y - 2, sz(tgt.y)))
        waypoints.push(new THREE.Vector3(sx(tgt.x), DEVICE_Y, sz(tgt.y)))
      } else {
        for (let gi = 0; gi < pts2d.length; gi++) {
          waypoints.push(new THREE.Vector3(sx(pts2d[gi].x), ANCHOR_Y, sz(pts2d[gi].y)))
        }
      }

      const beamMat = new THREE.LineBasicMaterial({ color: beamColor, transparent: true, opacity: p.active ? 0.8 : 0.5 })
      const beamGeo = new THREE.BufferGeometry().setFromPoints(waypoints)
      const beamLine = new THREE.Line(beamGeo, beamMat)
      scene.add(beamLine)
      meshGroups.beams.push(beamLine)

      const glMat = new THREE.LineBasicMaterial({ color: glowColor, transparent: true, opacity: 0.2 })
      const glLine = new THREE.Line(beamGeo.clone(), glMat)
      scene.add(glLine)
      meshGroups.beams.push(glLine)

      if (geoType === "multinode" && pts2d.length > 2) {
        for (let ri = 1; ri < pts2d.length - 1; ri++) {
          const relayGeo = new THREE.OctahedronGeometry(3)
          const relayMat = new THREE.MeshBasicMaterial({ color: 0xfbbf24, transparent: true, opacity: 0.6 })
          const relayMesh = new THREE.Mesh(relayGeo, relayMat)
          const ry = isDevice ? CEILING_Y - 2 : ANCHOR_Y
          relayMesh.position.set(sx(pts2d[ri].x), ry, sz(pts2d[ri].y))
          scene.add(relayMesh)
          meshGroups.beams.push(relayMesh)
        }
      }

      if (isDevice && waypoints.length >= 4) {
        for (let ci = 1; ci < waypoints.length - 2; ci++) {
          const w0 = waypoints[ci]
          const w1 = waypoints[ci + 1]
          const hDx = w1.x - w0.x
          const hDz = w1.z - w0.z
          const hLen = math.sqrt(hDx * hDx + hDz * hDz)
          if (hLen > 1) {
            const conduitGeo = new THREE.CylinderGeometry(1.5, 1.5, hLen, 8, 1, true)
            const conduitMat = new THREE.MeshBasicMaterial({ color: beamColor, transparent: true, opacity: 0.12, side: THREE.DoubleSide })
            const conduit = new THREE.Mesh(conduitGeo, conduitMat)
            conduit.position.set((w0.x + w1.x) / 2, (w0.y + w1.y) / 2, (w0.z + w1.z) / 2)
            conduit.lookAt(w1.x, w1.y, w1.z)
            conduit.rotateX(math.PI / 2)
            scene.add(conduit)
            meshGroups.beams.push(conduit)
          }
        }
      }

      const particleCount = 20
      const particleGeo = new THREE.BufferGeometry()
      const positions = new Float32Array(particleCount * 3)
      particleGeo.setAttribute("position", new THREE.BufferAttribute(positions, 3))
      const particleMat = new THREE.PointsMaterial({ color: glowColor, size: 4, transparent: true, opacity: 0.9, sizeAttenuation: true })
      const particles = new THREE.Points(particleGeo, particleMat)
      scene.add(particles)
      meshGroups.beams.push(particles)

      let totalLen = 0
      const segLens = []
      for (let s = 0; s < waypoints.length - 1; s++) {
        const sLen = waypoints[s].distanceTo(waypoints[s + 1])
        segLens.push(sLen)
        totalLen += sLen
      }

      particleSystems.push({
        mesh: particles,
        waypoints: waypoints.map(function(w) { return w.clone() }),
        segLens: segLens,
        totalLen: totalLen,
        count: particleCount,
      })
    })
  }

  // ── Animation loop ──
  function animate() {
    if (!renderer || !scene || !camera) return
    frameCount++

    // Animate beam particles along waypoint paths
    particleSystems.forEach(function(ps) {
      const positions = ps.mesh.geometry.attributes.position.array
      for (let i = 0; i < ps.count; i++) {
        const t = ((frameCount * 2 + i * (1000 / ps.count)) % 1000) / 1000
        const dist = t * ps.totalLen
        let accumulated = 0
        let px = ps.waypoints[0].x
        let py = ps.waypoints[0].y
        let pz = ps.waypoints[0].z
        for (let s = 0; s < ps.segLens.length; s++) {
          if (accumulated + ps.segLens[s] >= dist) {
            const segT = (dist - accumulated) / ps.segLens[s]
            const w0 = ps.waypoints[s]
            const w1 = ps.waypoints[s + 1]
            px = w0.x + (w1.x - w0.x) * segT
            py = w0.y + (w1.y - w0.y) * segT
            pz = w0.z + (w1.z - w0.z) * segT
            break
          }
          accumulated += ps.segLens[s]
        }
        positions[i * 3] = px
        positions[i * 3 + 1] = py
        positions[i * 3 + 2] = pz
      }
      ps.mesh.geometry.attributes.position.needsUpdate = true
    })

    // Pulse anchor spheres
    meshGroups.anchors.forEach(function(m) {
      if (m.userData && m.userData.type === "anchor") {
        const pulse = 0.9 + 0.1 * math.sin(frameCount * 0.04 + m.userData.ref.pulse)
        m.scale.setScalar(pulse)
      }
    })

    // Rotate connected device cubes
    meshGroups.devices.forEach(function(m) {
      if (m.userData && m.userData.type === "device" && m.userData.ref.connected) {
        m.rotation.y += 0.008
      }
    })

    // Pulse anchor lights
    anchorLights.forEach(function(l, idx) {
      l.intensity = 0.4 + 0.2 * math.sin(frameCount * 0.03 + idx * 1.5)
    })

    controls.update()
    renderer.render(scene, camera)
  }

  function resize(width, height) {
    if (!camera || !renderer) return
    camera.aspect = width / height
    camera.updateProjectionMatrix()
    renderer.setSize(width, height)
  }

  function destroy() {
    clearDynamic()
    if (renderer) {
      renderer.dispose()
      if (renderer.domElement && renderer.domElement.parentNode) {
        renderer.domElement.parentNode.removeChild(renderer.domElement)
      }
    }
    scene = null
    camera = null
    renderer = null
    controls = null
    container = null
    meshGroups = { anchors: [], devices: [], beams: [], walls: [], zones: [], labels: [], floor: null, ceiling: null }
    particleSystems = []
    anchorLights = []
    frameCount = 0
  }

  function isAvailable() {
    return typeof THREE !== "undefined"
  }

  return {
    init: init,
    buildScene: buildScene,
    animate: animate,
    resize: resize,
    destroy: destroy,
    isAvailable: isAvailable,
  }
})()


